import { GoogleGenAI } from "@google/genai";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async chat(prompt: string): Promise<string> {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          systemInstruction: "You are the NovaFlow AI Concierge. You are helpful, sleek, and technical. You answer questions about SaaS, Web Development, and NovaFlow's capabilities. Keep responses concise and modern.",
          temperature: 0.7,
        }
      });
      return response.text || "I'm sorry, I couldn't process that request.";
    } catch (error) {
      console.error("Gemini Error:", error);
      return "An error occurred while communicating with the AI. Please try again later.";
    }
  }
}

export const geminiService = new GeminiService();

