const AIChatPreview: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'assistant', content: 'Hello! I am the NovaFlow AI assistant. How can I help you build today?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMessage }]);
    setIsLoading(true);

    const response = await geminiService.chat(userMessage);

    setMessages(prev => [...prev, { role: 'assistant', content: response }]);
    setIsLoading(false);
  };

  return (
    <section id="demo" className="py-24">
      <div className="container mx-auto px-6">
        <div className="max-w-4xl mx-auto glass-card rounded-[2.5rem] overflow-hidden shadow-2xl border border-gray-800">
          <div className="grid md:grid-cols-[1fr_1.5fr]">
            {/* Left: Branding/Copy */}
            <div className="p-10 bg-indigo-600/10 flex flex-col justify-center border-r border-gray-800">
              <div className="w-12 h-12 bg-indigo-600 rounded-xl flex items-center justify-center mb-6">
                <Bot className="text-white" />
              </div>
              <h2 className="text-3xl font-bold mb-4">Integrated Intelligence</h2>
              <p className="text-gray-400 mb-6 text-sm leading-relaxed">
                Experience the power of native Gemini orchestration. Ask anything about our platform or web dev.
              </p>
              <div className="space-y-3">
                <div className="flex items-center text-xs text-gray-500">
                  <div className="w-2 h-2 rounded-full bg-green-500 mr-2"></div>
                  Real-time Context Aware
                </div>
                <div className="flex items-center text-xs text-gray-500">
                  <div className="w-2 h-2 rounded-full bg-green-500 mr-2"></div>
                  Zero-latency Inference
                </div>
              </div>
            </div>

            {/* Right: Chat UI */}
            <div className="flex flex-col h-[500px]">
              <div className="flex-1 overflow-y-auto p-6 space-y-6" ref={scrollRef}>
                {messages.map((msg, idx) => (
                  <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[85%] flex space-x-3 ${msg.role === 'user' ? 'flex-row-reverse space-x-reverse' : ''}`}>
                      <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${msg.role === 'user' ? 'bg-indigo-600' : 'bg-gray-800'}`}>
                        {msg.role === 'user' ? <User size={16} /> : <Bot size={16} />}
                      </div>
                      <div className={`p-4 rounded-2xl text-sm leading-relaxed ${msg.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-gray-900 border border-gray-800 text-gray-300 rounded-tl-none'}`}>
                        {msg.content}
                      </div>
                    </div>
                  </div>
                ))}
                {isLoading && (
                  <div className="flex justify-start">
                    <div className="flex space-x-3 items-center text-gray-500 text-xs italic">
                      <Loader2 className="animate-spin w-4 h-4" />
                      <span>Gemini is thinking...</span>
                    </div>
                  </div>
                )}
              </div>

              <form onSubmit={handleSubmit} className="p-4 border-t border-gray-800 bg-gray-900/50 flex space-x-2">
                <input 
                  type="text" 
