import { GoogleGenAI } from "@google/genai";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async analyzeWriting(text: string): Promise<string> {
    const prompt = `
      请作为一名资深语文特级教师，对以下学生习作进行“过程性辅导”诊断。

      要求：
      1. 首先识别文体（记叙文、议论文、说明文或其他）。
      2. 根据文体进行针对性评价：
         - 记叙文：检查六要素（时地人起经结）、修辞手法、环境描写、主旨。
         - 说明文：检查说明方法（举例子、打比方、列数字等）及语言准确性。
         - 议论文：检查论点是否明确、论据是否充分、是否存在逻辑漏洞（如以偏概全）。
      3. 给出 3 条具体的、启发式的修改建议。
      4. 严禁代写整篇文章，必须以指导者的身份给反馈。

      习作内容：
      ${text}
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          temperature: 0.8,
        }
      });
      return response.text || "无法生成反馈，请稍后再试。";
    } catch (error) {
      console.error("Gemini Error:", error);
      return "诊断过程遇到小问题，请检查网络后重试。";
    }
  }
}

export const geminiService = new GeminiService();

import React, { useState, useRef, useEffect } from 'react';
import { Send, BookOpen, PenLine, Sparkles, Loader2, ClipboardCheck, History } from 'lucide-react';
import { geminiService } from '../services/geminiService';

const CompositionWorkspace: React.FC = () => {
  const [content, setContent] = useState('');
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [wordCount, setWordCount] = useState(0);

  useEffect(() => {
    setWordCount(content.length);
  }, [content]);

  const handleAnalyze = async () => {
    if (!content.trim() || isAnalyzing) return;
    setIsAnalyzing(true);
    setAnalysis(null);

    const result = await geminiService.analyzeWriting(content);
    setAnalysis(result);
    setIsAnalyzing(false);
  };

  return (
    <section id="demo" className="py-24 relative">
      <div className="container mx-auto px-6">
        <div className="text-center mb-12">
          <h2 className="text-4xl font-bold mb-4 gradient-heading">智能写作工作台</h2>
          <p className="text-slate-400">在灵感流淌间，获得即时的名师级诊断与反馈</p>
        </div>

        <div className="grid lg:grid-cols-[1.5fr_1fr] gap-8 max-w-7xl mx-auto h-[700px]">
          {/* 左侧：写作区 */}
          <div className="flex flex-col paper-card rounded-[2rem] border border-slate-800 overflow-hidden shadow-2xl">
            <div className="flex items-center justify-between px-8 py-4 bg-slate-900/50 border-b border-slate-800">
              <div className="flex items-center space-x-2">
                <PenLine className="text-red-400 w-5 h-5" />
                <span className="font-semibold text-slate-200">正在创作...</span>
              </div>
              <div className="text-xs text-slate-500 font-mono">字数：{wordCount}</div>
            </div>
            <textarea
              value={content}
              onChange={(e) => setContent(e.target.value)}
              placeholder="请在此输入你的作文内容..."
