import { GoogleGenAI } from "@google/genai";

export class GeminiService {
  /**
   * Performs deep analysis on a writing sample based on its genre.
   */
  async analyzeWriting(text: string): Promise<string> {
    // ALWAYS initialize a fresh instance with process.env.API_KEY
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const prompt = `
      请作为一名资深语文特级教师，对以下学生习作进行“过程性辅导”诊断。

      要求：
      1. 首先识别文体（记叙文、议论文、说明文或其他）。
      2. 根据文体进行针对性评价：
         - 记叙文：检查六要素（时地人起经结）、修辞手法、环境描写、主旨。
         - 说明文：检查说明方法（举例子、打比方、列数字等）及语言准确性。
         - 议论文：检查论点是否明确、论据是否充分、是否存在逻辑漏洞（如以偏概全）。
      3. 给出 3 条具体的、启发式的修改建议。
      4. 严禁代写整篇文章，必须以指导者的身份给反馈。

      习作内容：
      ${text}
    `;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          temperature: 0.8,
        }
      });
      // Correct usage: Access .text property directly
      return response.text || "无法生成反馈，请稍后再试。";
    } catch (error) {
      console.error("Gemini Error:", error);
      return "诊断过程遇到小问题，请检查网络后重试。";
    }
  }

  /**
   * Handles general chat interactions for the tutor persona.
   * This fixes the missing 'chat' method error in AIChatPreview.tsx.
   */
  async chat(message: string): Promise<string> {
    // ALWAYS initialize a fresh instance with process.env.API_KEY
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: message,
        config: {
          systemInstruction: "你是一个专业的作文辅导助手，名叫“语智笔”。你的回答应具有启发性，通过提问和建议引导学生进步，拒绝直接代写。",
        }
      });
      // Correct usage: Access .text property directly
      return response.text || "抱歉，请再说一次。";
    } catch (error) {
      console.error("Gemini Chat Error:", error);
      return "对话服务暂时不可用。";
    }
  }
}

