import { GoogleGenAI } from "@google/genai";

export class GeminiService {
  /**
   * 深度分析写作内容（纯文本或带附件）
   */
  async analyzeWriting(text: string, attachment?: { data: string; mimeType: string }): Promise<{ extractedText?: string; analysis: string }> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const systemInstruction = `
      请作为一名资深语文特级教师，对学生习作进行“过程性辅导”诊断。
      如果是图片或PDF，请先精准提取其中的文字内容。

      反馈要求：
      1. 识别文体（记叙文、议论文、说明文等）。
      2. 针对性评价：
         - 记叙文：检查六要素（时地人起经结）、修辞手法、主旨。
         - 说明文：检查说明方法及准确性。
         - 议论文：检查论点论据及逻辑漏洞。
      3. 给出 3 条具体的启发式修改建议。
      4. 严禁代写。

      输出格式：
      [EXTRACTED_TEXT]
      (这里放提取出的习作正文，如果没有附件则不写这部分)
      [/EXTRACTED_TEXT]

      [ANALYSIS]
      (这里放你的详细诊断报告)
      [/ANALYSIS]
    `;

    try {
      let contents: any;
      if (attachment) {
        contents = {
          parts: [
            { inlineData: { data: attachment.data, mimeType: attachment.mimeType } },
            { text: text || "请识别并分析这份文档中的作文内容。" }
          ]
        };
      } else {
        contents = text;
      }

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: contents,
        config: {
          systemInstruction: systemInstruction,
          temperature: 0.7,
        }
      });

      const fullResponse = response.text || "";
      const extractedMatch = fullResponse.match(/\[EXTRACTED_TEXT\]([\s\S]*?)\[\/EXTRACTED_TEXT\]/);
      const analysisMatch = fullResponse.match(/\[ANALYSIS\]([\s\S]*?)\[\/ANALYSIS\]/);

      return {
        extractedText: extractedMatch ? extractedMatch[1].trim() : undefined,
        analysis: analysisMatch ? analysisMatch[1].trim() : (fullResponse.replace(/\[EXTRACTED_TEXT\].*?\[\/EXTRACTED_TEXT\]/s, '').trim())
      };
    } catch (error) {
      console.error("Gemini Multi-modal Error:", error);
      throw error;
    }
  }

  async chat(message: string): Promise<string> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: message,
        config: {
          systemInstruction: "你是一个专业的作文辅导助手，名叫“语智笔”。引导学生进步，拒绝直接代写。",
        }
      });
      return response.text || "抱歉，请再说一次。";
    } catch (error) {
      return "对话服务暂时不可用。";
    }
  }
}

