    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if ((!content.trim() && !fileData) || isAnalyzing) return;
    setIsAnalyzing(true);
    setAnalysis(null);

    try {
      const result = await geminiService.analyzeWriting(content, fileData || undefined);

      if (result.extractedText) {
        setContent(result.extractedText);
      }
      setAnalysis(result.analysis);
    } catch (err) {
      setAnalysis("发生错误，请重试。");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const exportReport = () => {
    if (!analysis) return;
    const reportHeader = `# 语智笔 - 作文智能诊断报告\n\n## 习作正文\n${content || "见附件内容"}\n\n`;
