class AuthService {
  // 模拟从本地存储读取用户信息，实际应从 Supabase 读取
  private STORAGE_KEY = 'scribewise_user';

  getUser(): User {
    const stored = localStorage.getItem(this.STORAGE_KEY);
    if (stored) return JSON.parse(stored);

    // 默认游客用户
    const defaultUser: User = {
      id: 'ID-' + Math.random().toString(36).substr(2, 9),
      tier: 'free',
      dailyCount: 3
    };
    this.saveUser(defaultUser);
    return defaultUser;
  }

  saveUser(user: User) {
    localStorage.setItem(this.STORAGE_KEY, JSON.stringify(user));
  }

  /**
   * 激活码校验逻辑
   * 在生产环境下，这应该是一个 Serverless Function (Vercel API) 
   * 调用数据库比对码和绑定状态
   */
  async activate(code: string, userId: string): Promise<{ success: boolean; tier?: UserTier; message: string }> {
    // 模拟激活码逻辑
    const codeMap: Record<string, UserTier> = {
      'PRO-666': 'pro',
      'PLUS-888': 'plus',
      'ADMIN-999': 'custom'
    };

    return new Promise((resolve) => {
      setTimeout(() => {
        const tier = codeMap[code.toUpperCase()];
        if (tier) {
          const user = this.getUser();
          user.tier = tier;
          user.activatedAt = new Date().toISOString();
          this.saveUser(user);
          resolve({ success: true, tier, message: `激活成功！您已升级为 ${tier.toUpperCase()} 会员。` });
        } else {
          resolve({ success: false, message: '无效的激活码或已被绑定。' });
        }
      }, 1000);
    });
  }
}

