import { supabase } from './supabaseClient';

class AuthService {
  /**
   * 获取当前登录用户状态
   */
  async getCurrentUser(): Promise<User | null> {
    const { data: { user: authUser } } = await supabase.auth.getUser();
    if (!authUser) return null;

    const { data: profile } = await supabase
      .from('profiles')
      .select('*')
      .eq('id', authUser.id)
      .single();

    return {
      id: authUser.id,
      email: authUser.email,
      tier: profile?.tier || 'free',
      dailyCount: profile?.daily_count || 0
    };
  }

  /**
   * 调用后端 Serverless Function 激活码
   * 必须通过后端处理，防止用户直接通过前端修改自己的等级
   */
  async activate(code: string): Promise<{ success: boolean; message: string }> {
    try {
      // 这里的 /api/activate 是我们将要在 Vercel 部署的后端接口
      const response = await fetch('/api/activate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ code })
      });

      const result = await response.json();
      return result;
    } catch (error) {
      return { success: false, message: '系统繁忙，请稍后再试。' };
    }
  }

  /**
   * 简单的注册/登录功能（这里演示 ID 绑定逻辑）
   * 商业版建议引导用户使用邮箱注册
   */
  async signInAnonymously() {
    const { data, error } = await supabase.auth.signInAnonymously();
    return { data, error };
  }
}

export const authService = new AuthService();

import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.0';

/**
 * 此文件部署在 vercel 的 /api 目录下
 * 使用 SERVICE_ROLE_KEY 绕过 RLS 执行管理操作
 */
export default async function handler(req: any, res: any) {
  if (req.method !== 'POST') return res.status(405).json({ message: 'Method not allowed' });

  const { code } = req.body;
  const supabase = createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.SUPABASE_SERVICE_ROLE_KEY! // 管理员权限
  );

  // 1. 验证用户登录状态
  const authHeader = req.headers.authorization;
  const { data: { user }, error: authError } = await supabase.auth.getUser(authHeader);

  if (authError || !user) {
    return res.status(401).json({ success: false, message: '请先登录' });
  }

  // 2. 检查激活码有效性
  const { data: activation, error: codeError } = await supabase
    .from('activation_codes')
    .select('*')
    .eq('code', code.toUpperCase())
    .eq('is_used', false)
    .single();

  if (codeError || !activation) {
    return res.status(400).json({ success: false, message: '激活码无效或已被使用' });
  }

  // 3. 执行原子操作：更新用户等级 + 标记激活码已使用
  const { error: updateProfileError } = await supabase
    .from('profiles')
    .update({ tier: activation.tier, updated_at: new Date() })
    .eq('id', user.id);

  if (updateProfileError) return res.status(500).json({ success: false, message: '升级资料失败' });

  await supabase
    .from('activation_codes')
    .update({ is_used: true, used_by: user.id, used_at: new Date() })
    .eq('code', code.toUpperCase());

  return res.status(200).json({ 
    success: true, 
    tier: activation.tier,
    message: `恭喜！成功激活 ${activation.tier} 权限。` 
  });
}

