import { User, UserTier } from '../types';
import { supabase } from './supabaseClient';

class AuthService {
  /**
   * 获取当前登录用户状态
   */
  async getCurrentUser(): Promise<User | null> {
    if (!supabase) return this.getMockUser();

    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session?.user) return null;

      const { data: profile } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', session.user.id)
        .single();

      return {
        id: session.user.id,
        email: session.user.email,
        tier: profile?.tier || 'free',
        dailyCount: profile?.daily_count || 0
      };
    } catch (e) {
      console.warn("Supabase auth error:", e);
      return this.getMockUser();
    }
  }

  /**
   * 调用后端 Serverless Function 激活码
   * 必须发送 Authorization Header
   */
  async activate(code: string): Promise<{ success: boolean; message: string }> {
    if (!supabase) {
      return { success: false, message: '数据库未连接' };
    }

    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) return { success: false, message: '请先登录' };

      const response = await fetch('/api/activate', {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${session.access_token}` // 发送身份令牌
        },
        body: JSON.stringify({ code })
      });

      const result = await response.json();
      return result;
    } catch (error) {
      return { success: false, message: '激活请求失败' };
    }
  }

  private getMockUser(): User {
    return { id: 'LOCAL-USER', tier: 'free', dailyCount: 3 };
  }

  async signInAnonymously() {
    if (!supabase) return { data: null, error: new Error("Supabase not initialized") };
    return await supabase.auth.signInAnonymously();
  }
}

export const authService = new AuthService();

import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.0';

export default async function handler(req: any, res: any) {
  if (req.method !== 'POST') return res.status(405).json({ message: 'Method not allowed' });

  const { code } = req.body;
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ success: false, message: '未授权访问' });
  }

  const token = authHeader.split(' ')[1];
  const supabaseAdmin = createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.SUPABASE_SERVICE_ROLE_KEY!
  );

  // 1. 验证用户令牌
  const { data: { user }, error: authError } = await supabaseAdmin.auth.getUser(token);

  if (authError || !user) {
    return res.status(401).json({ success: false, message: '身份验证过期，请刷新页面' });
  }

  // 2. 检查激活码
  const { data: activation, error: codeError } = await supabaseAdmin
    .from('activation_codes')
    .select('*')
    .eq('code', code.toUpperCase())
    .eq('is_used', false)
    .single();

  if (codeError || !activation) {
    return res.status(400).json({ success: false, message: '激活码无效或已被使用' });
  }

  // 3. 更新
  const { error: updateError } = await supabaseAdmin
    .from('profiles')
    .update({ tier: activation.tier, updated_at: new Date() })
    .eq('id', user.id);

  if (updateError) return res.status(500).json({ success: false, message: '资料更新失败' });

  await supabaseAdmin
    .from('activation_codes')
    .update({ is_used: true, used_by: user.id, used_at: new Date() })
    .eq('code', code.toUpperCase());

  return res.status(200).json({ 
    success: true, 
    message: `成功激活 ${activation.tier.toUpperCase()} 会员！` 
  });
}

