const CompositionWorkspace: React.FC<Props> = ({ user }) => {
  const [content, setContent] = useState('');
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [fileData, setFileData] = useState<{ data: string; mimeType: string; name: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const canUpload = user.tier === 'plus' || user.tier === 'custom';
  const canExport = user.tier === 'plus' || user.tier === 'custom';

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!canUpload) {
      alert("附件识别为 Plus 会员专属功能。");
      return;
    }
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = (event.target?.result as string).split(',')[1];
      setFileData({ data: base64, mimeType: file.type, name: file.name });
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if ((!content.trim() && !fileData) || isAnalyzing) return;
    setIsAnalyzing(true);
    setAnalysis(null);

    try {
      const result = await geminiService.analyzeWriting(content, fileData || undefined);
      if (result.extractedText) setContent(result.extractedText);
      setAnalysis(result.analysis);
    } catch (err) {
      setAnalysis("发生错误，请检查 API Key 或重试。");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const exportReport = () => {
    if (!canExport) {
      alert("报告导出为 Plus 会员专属功能。");
      return;
