/**
 * 安全获取环境变量的辅助函数
 * 在 Vite 构建的浏览器环境中，直接访问 process.env 可能会导致错误
 */
const getEnv = (key: string): string | undefined => {
  try {
    // 优先尝试从全局 process 对象读取（通常由 Vercel 或构建工具注入）
    if (typeof process !== 'undefined' && process.env && process.env[key]) {
      return process.env[key];
    }
    // 兼容 Vite 默认的 import.meta.env
    // @ts-ignore
    if (typeof import.meta !== 'undefined' && import.meta.env && import.meta.env[key]) {
      // @ts-ignore
      return import.meta.env[key];
    }
    // 尝试直接从全局变量读取（如果是在 index.html 中通过 script 注入的）
    // @ts-ignore
    if (window.process?.env?.[key]) {
      // @ts-ignore
      return window.process.env[key];
    }
  } catch (e) {
    console.warn(`Error accessing environment variable ${key}:`, e);
  }
  return undefined;
};

