 * 遵循 @google/genai 最新编码规范
 */
export class GeminiService {
  /**
   * 深度分析写作内容
   */
  async analyzeWriting(text: string, attachment?: { data: string; mimeType: string }): Promise<{ extractedText?: string; analysis: string }> {
    // 必须直接使用 process.env.API_KEY
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const systemInstruction = `
      请作为一名资深语文特级教师，对学生习作进行“过程性辅导”诊断。
      如果是图片或PDF，请先精准提取其中的文字内容。

      反馈要求：
      1. 识别文体。
      2. 针对性评价（记叙文六要素/议论文逻辑漏洞）。
      3. 给出 3 条启发式修改建议。

      输出格式：
      [EXTRACTED_TEXT](提取内容)[/EXTRACTED_TEXT]
      [ANALYSIS](诊断报告)[/ANALYSIS]
    `;

    try {
      const contents = attachment ? {
        parts: [
          { inlineData: { data: attachment.data, mimeType: attachment.mimeType } },
          { text: text || "请识别并分析这份文档中的作文内容。" }
        ]
      } : { parts: [{ text }] };

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: contents,
        config: { 
          systemInstruction, 
          temperature: 0.7 
        }
      });

      // 使用 .text 属性获取内容（注意：不是方法调用）
      const fullResponse = response.text || "";
      const extractedMatch = fullResponse.match(/\[EXTRACTED_TEXT\]([\s\S]*?)\[\/EXTRACTED_TEXT\]/);
      const analysisMatch = fullResponse.match(/\[ANALYSIS\]([\s\S]*?)\[\/ANALYSIS\]/);

      return {
        extractedText: extractedMatch ? extractedMatch[1].trim() : undefined,
        analysis: analysisMatch ? analysisMatch[1].trim() : fullResponse
      };
    } catch (error: any) {
      console.error("Gemini Analyze Error:", error);
      throw new Error(error.message || "分析服务暂时不可用");
    }
  }

  /**
   * 基础辅导对话
   */
  async chat(message: string): Promise<string> {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: message,
        config: {
          systemInstruction: "你是一个专业的初高中作文辅导助手，名叫“语智笔”。请用亲切、专业的语气回答学生的写作疑问。",
        }
      });
      // 规范要求使用 response.text 获取结果
      return response.text || "抱歉，我刚才走神了，请再说一次。";
    } catch (error: any) {
      console.error("Gemini Chat Error:", error);
      if (error.message?.includes("API_KEY")) {
        return "配置错误：API Key 校验失败。请确保 Vercel 中已正确设置 VITE_API_KEY。";
      }
      return "对话服务暂时不可用，请稍后再试。";
    }
  }
}

