import { User } from '../types.ts';
import { supabase } from './supabaseClient.ts';

class AuthService {
  async getCurrentUser(): Promise<User | null> {
    if (!supabase) return this.getMockUser();

    try {
      const { data: sessionData, error: sessionError } = await supabase.auth.getSession();
      if (sessionError || !sessionData?.session?.user) {
        return this.getMockUser(); // 即使没 session，也返回 Mock 用户确保界面显示
      }

      const user = sessionData.session.user;
      const { data: profile, error: profileError } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', user.id)
        .single();

      if (profileError || !profile) {
        return {
          id: user.id,
          email: user.email,
          tier: 'free',
          dailyCount: 0
        };
      }

      return {
        id: user.id,
        email: user.email,
        tier: profile.tier || 'free',
        dailyCount: profile.daily_count || 0
      };
    } catch (e) {
      console.warn("Supabase auth error, falling back to mock:", e);
      return this.getMockUser();
    }
  }

  async activate(code: string): Promise<{ success: boolean; message: string }> {
    if (!supabase) return { success: false, message: '数据库未连接' };

    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) return { success: false, message: '请先登录' };

      const response = await fetch('/api/activate', {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${session.access_token}`
        },
        body: JSON.stringify({ code })
      });

      return await response.json();
    } catch (error) {
      return { success: false, message: '激活请求失败' };
    }
  }

  private getMockUser(): User {
    // 默认给 PLUS 等级，方便用户立即体验 OCR/PDF 辅导功能
    return { id: 'LOCAL-TESTER', tier: 'plus', dailyCount: 10 };
  }

  async signInAnonymously() {
    if (!supabase) return { data: null, error: new Error("Supabase not initialized") };
    try {
      return await supabase.auth.signInAnonymously();
    } catch (e) {
      return { data: null, error: e };
    }
  }
}

