import React, { useState, useRef } from 'react';
import { 
  PenLine, Sparkles, Loader2, 
  ClipboardCheck, History, Upload, FileText, 
  Image as ImageIcon, Download, Trash2, Lock, AlertCircle
} from 'lucide-react';
import { geminiService } from '../services/geminiService.ts';
import { User } from '../types.ts';

interface Props {
  user: User;
}

const CompositionWorkspace: React.FC<Props> = ({ user }) => {
  const [content, setContent] = useState('');
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [fileData, setFileData] = useState<{ data: string; mimeType: string; name: string } | null>(null);
  const [error, setError] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // 只要是 plus 及以上等级，或者处于测试模式，均允许上传
  const canUpload = user.tier === 'plus' || user.tier === 'custom' || user.id === 'LOCAL-TESTER';

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!canUpload) {
      alert("附件识别为 Plus 会员专属功能。");
      return;
    }
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 10 * 1024 * 1024) {
      alert("文件过大，请上传 10MB 以内的图片或 PDF。");
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = (event.target?.result as string).split(',')[1];
      setFileData({ data: base64, mimeType: file.type, name: file.name });
      setError(null);
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if ((!content.trim() && !fileData) || isAnalyzing) return;
    setIsAnalyzing(true);
    setAnalysis(null);
    setError(null);

    try {
      const result = await geminiService.analyzeWriting(content, fileData || undefined);
      if (result.extractedText) {
        setContent(result.extractedText);
      }
      setAnalysis(result.analysis);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "分析失败，请检查网络或配置。");
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <section id="demo" className="py-12 relative">
      <div className="container mx-auto px-6">
        <div className="grid lg:grid-cols-[1.5fr_1fr] gap-8 max-w-7xl mx-auto min-h-[700px]">
          {/* 左侧：输入与上传区 */}
          <div className="flex flex-col paper-card rounded-[2rem] border border-slate-800 overflow-hidden shadow-2xl">
            <div className="flex items-center justify-between px-8 py-5 bg-slate-900/50 border-b border-slate-800">
              <div className="flex items-center space-x-2">
                <PenLine className="text-red-400 w-5 h-5" />
                <span className="font-bold text-slate-100">创作辅导中心</span>
                <span className="text-[10px] bg-red-600/20 text-red-400 px-2 py-0.5 rounded-full font-mono uppercase border border-red-500/20">
                  {user.tier}
                </span>
              </div>

              <div className="flex items-center space-x-3">
                <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept=".pdf,image/*" />
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className={`flex items-center space-x-2 text-xs px-4 py-2 rounded-xl border font-bold transition-all shadow-lg ${canUpload ? 'bg-red-600/10 hover:bg-red-600/20 text-red-400 border-red-500/30' : 'bg-slate-900/50 text-slate-600 border-slate-800'}`}
                >
                  {canUpload ? <Upload size={14} /> : <Lock size={14} />}
                  <span>拍照/PDF 导入</span>
                </button>
              </div>
            </div>

            {fileData && (
              <div className="bg-red-600/10 px-8 py-3 flex items-center justify-between border-b border-red-500/20 animate-in fade-in slide-in-from-top-2">
                <div className="flex items-center space-x-3 text-red-400 text-xs font-medium">
                  {fileData.mimeType.includes('pdf') ? <FileText size={16} /> : <ImageIcon size={16} />}
                  <span className="truncate max-w-[200px]">{fileData.name}</span>
                  <span className="opacity-60">(待识别)</span>
                </div>
                <button onClick={() => setFileData(null)} className="p-1 hover:bg-red-600/20 rounded-full transition-colors">
                  <Trash2 size={16} className="text-red-400" />
                </button>
              </div>
            )}

            <textarea
              value={content}
              onChange={(e) => setContent(e.target.value)}
              placeholder={fileData ? "已选择文件，点击下方按钮开始识别并分析..." : "在此输入习作正文，或者使用上方按钮拍照导入..."}
              className="flex-1 p-8 bg-transparent text-slate-200 resize-none focus:outline-none text-lg leading-relaxed placeholder:text-slate-700 scroll-custom"
            />

            <div className="p-6 bg-slate-900/30 border-t border-slate-800 flex items-center justify-between">
              <div className="text-[10px] text-slate-500 font-medium uppercase tracking-widest px-2">
                {content.length} 字
              </div>
              <button 
                onClick={handleAnalyze}
                disabled={isAnalyzing || (!content.trim() && !fileData)}
                className="group flex items-center space-x-3 px-12 py-4 bg-red-600 hover:bg-red-700 disabled:bg-slate-800 text-white font-bold rounded-2xl shadow-2xl shadow-red-600/20 transition-all active:scale-95"
              >
                {isAnalyzing ? <Loader2 className="animate-spin" /> : <Sparkles className="group-hover:rotate-12 transition-transform" />}
                <span>{fileData ? '智能识别并分析' : '开始辅导'}</span>
              </button>
            </div>
          </div>

          {/* 右侧：分析报告区 */}
          <div className="flex flex-col paper-card rounded-[2rem] border border-slate-800 overflow-hidden bg-slate-950/50">
            <div className="px-8 py-5 bg-slate-900/50 border-b border-slate-800 flex items-center justify-between">
              <div className="flex items-center space-x-2 font-bold">
                <ClipboardCheck className="text-green-400 w-5 h-5" />
                <span className="text-slate-100">诊断报告</span>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-8 scroll-custom relative">
              {isAnalyzing && (
                <div className="absolute inset-0 bg-slate-950/40 backdrop-blur-[2px] z-10 flex flex-col items-center justify-center space-y-4">
                  <div className="relative">
                    <Loader2 className="animate-spin text-red-500 w-12 h-12" />
                    <Sparkles className="absolute -top-1 -right-1 text-red-400 w-4 h-4 animate-pulse" />
                  </div>
                  <p className="text-sm font-bold text-red-400 animate-pulse tracking-widest">正在深度分析习作...</p>
                </div>
              )}

              {error && (
                <div className="p-4 bg-red-600/10 border border-red-500/20 rounded-2xl flex items-start space-x-3 mb-6">
                  <AlertCircle className="text-red-500 flex-shrink-0 mt-0.5" size={18} />
                  <p className="text-xs text-red-400 leading-relaxed font-medium">{error}</p>
                </div>
              )}

              {analysis ? (
                <div className="prose prose-invert prose-red whitespace-pre-wrap animate-in fade-in duration-700">
                  {analysis}
                </div>
              ) : !isAnalyzing && (
                <div className="h-full flex flex-col items-center justify-center opacity-20 text-center px-12">
                  <History size={64} className="mb-6 stroke-[1px]" />
                  <p className="text-base font-medium">暂无诊断报告</p>
                  <p className="text-xs mt-2">在左侧输入内容或上传图片，即可获得特级教师级别的指导建议。</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

