/**
 * 安全地获取环境变量，防止在某些环境下 import.meta.env 为 undefined 导致崩溃
 */
const getSafeEnv = () => {
  try {
    // @ts-ignore
    return import.meta.env || {};
  } catch (e) {
    return {};
  }
};

const env = getSafeEnv();

const getEnvValue = (key: string): string | undefined => {
  // 1. 尝试标准变量名
  if (env[`VITE_${key}`]) return env[`VITE_${key}`];
  if (env[`NEXT_PUBLIC_${key}`]) return env[`NEXT_PUBLIC_${key}`];

  // 2. 特殊容错：处理常见的拼写错误 (如 UR 漏写 L)
  if (key === 'SUPABASE_URL' && env['VITE_SUPABASE_UR']) return env['VITE_SUPABASE_UR'];

  // 3. 尝试 window.process (兜底)
  try {
    const pEnv = (window as any).process?.env || {};
    return pEnv[`VITE_${key}`] || pEnv[`NEXT_PUBLIC_${key}`] || pEnv[key];
  } catch (e) {}

  return undefined;
};

// 安全获取 URL 和 Key
const url = env.VITE_SUPABASE_URL || env.NEXT_PUBLIC_SUPABASE_URL || getEnvValue('SUPABASE_URL');
const key = env.VITE_SUPABASE_ANON_KEY || env.NEXT_PUBLIC_SUPABASE_ANON_KEY || getEnvValue('SUPABASE_ANON_KEY');

// 导出客户端实例
export const supabase = (url && key) ? createClient(url, key) : null;

// 在控制台打印诊断信息
if (!supabase) {
  console.group("⚠️ 语智笔：数据库连接诊断");
  console.log("检测到 URL:", url ? "✅ 已找到" : "❌ 未找到");
  console.log("检测到 Key:", key ? "✅ 已找到" : "❌ 未找到");
  console.info("应用将自动切换至【本地演示模式】，所有功能（包括 OCR）将默认开启。");
  console.groupEnd();
}

