// @ts-ignore
import { createClient } from '@supabase/supabase-js';

export default async function handler(req: any, res: any) {
  if (req.method !== 'POST') return res.status(405).json({ message: 'Method not allowed' });

  const { code } = req.body;
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ success: false, message: '未授权访问' });
  }

  // 服务端可以直接使用 process.env，不需要 VITE_ 前缀
  const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL || process.env.VITE_SUPABASE_URL || process.env.SUPABASE_URL;
  const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY;

  if (!supabaseUrl || !serviceKey) {
    return res.status(500).json({ success: false, message: '服务端配置缺失' });
  }

  const token = authHeader.split(' ')[1];
  const supabaseAdmin = createClient(supabaseUrl, serviceKey);

  // 1. 验证用户令牌
  const { data: { user }, error: authError } = await supabaseAdmin.auth.getUser(token);

  if (authError || !user) {
    return res.status(401).json({ success: false, message: '身份验证过期，请刷新页面' });
  }

  // 2. 检查激活码
  const { data: activation, error: codeError } = await supabaseAdmin
    .from('activation_codes')
    .select('*')
    .eq('code', code.toUpperCase())
    .eq('is_used', false)
    .single();

  if (codeError || !activation) {
    return res.status(400).json({ success: false, message: '激活码无效或已被使用' });
  }

  // 3. 更新用户资料和激活码状态
  const { error: updateError } = await supabaseAdmin
    .from('profiles')
    .update({ tier: activation.tier, updated_at: new Date() })
    .eq('id', user.id);

  if (updateError) return res.status(500).json({ success: false, message: '资料更新失败' });

  await supabaseAdmin
    .from('activation_codes')
    .update({ is_used: true, used_by: user.id, used_at: new Date() })
    .eq('code', code.toUpperCase());

  return res.status(200).json({ 
    success: true, 
    message: `成功激活 ${activation.tier.toUpperCase()} 会员！` 
  });
}

import React, { useState, useRef } from 'react';
import { 
  PenLine, Sparkles, Loader2, 
