} from 'lucide-react';
import { geminiService } from '../services/geminiService.ts';
import { User } from '../types.ts';

interface Props {
  user: User;
}

const CompositionWorkspace: React.FC<Props> = ({ user }) => {
  const [content, setContent] = useState('');
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [fileData, setFileData] = useState<{ data: string; mimeType: string; name: string } | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // 只要是 plus 及以上等级，或者处于测试模式，均允许上传
  const canUpload = user.tier === 'plus' || user.tier === 'custom' || user.id === 'LOCAL-TESTER';

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!canUpload) {
      alert("附件识别为 Plus 会员专属功能。");
      return;
    }
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 10 * 1024 * 1024) {
      alert("文件过大，请上传 10MB 以内的图片或 PDF。");
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = (event.target?.result as string).split(',')[1];
      setFileData({ data: base64, mimeType: file.type, name: file.name });
      setError(null);
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if ((!content.trim() && !fileData) || isAnalyzing) return;
    setIsAnalyzing(true);
    setAnalysis(null);
    setError(null);

    try {
      const result = await geminiService.analyzeWriting(content, fileData || undefined);
      if (result.extractedText) {
        setContent(result.extractedText);
      }
      setAnalysis(result.analysis);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "分析失败，请检查网络或配置。");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const copyToClipboard = () => {
    if (!analysis) return;
    navigator.clipboard.writeText(analysis);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <section id="demo" className="py-12 relative">
      <div className="container mx-auto px-6">
        <div className="grid lg:grid-cols-[1.5fr_1fr] gap-8 max-w-7xl mx-auto min-h-[700px]">
          {/* 左侧：输入与上传区 */}
          <div className="flex flex-col paper-card rounded-[2rem] border border-slate-800 overflow-hidden shadow-2xl transition-all hover:border-slate-700">
