import { GoogleGenAI } from "@google/genai";

/**
 * 语智笔 AI 服务
 * 遵循 @google/genai 最新编码规范
 */
export class GeminiService {
  /**
   * 核心分析逻辑：支持 OCR 识别后自动辅导
   */
  async analyzeWriting(text: string, attachment?: { data: string; mimeType: string }): Promise<{ extractedText?: string; analysis: string }> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const systemInstruction = `
      请作为一名资深语文特级教师，对学生习作进行“过程性辅导”诊断。

      你的目标不仅是纠错，更是引导学生思考如何写得更好。

      如果你收到了图片或 PDF，请在第一步【原文提取】中精准提取文字。
      然后针对内容进行以下诊断：
      1. 识别文体：明确指出文体（如：写人记事、写景状物、论证散文等）。
      2. 亮点赏析：发现文章中用得好的词语、修辞或精妙的结构。
      3. 核心问题诊断：
         - 记叙文：检查六要素是否齐全，情节是否有波澜。
         - 议论文：检查论点是否明确，论证是否严密，逻辑是否有断层。
      4. 过程性改进建议：给出 3 条具体的、可操作的修改方案，最好能提供一个示范性的句子改写。

      输出格式必须包含：
      [EXTRACTED_TEXT]此处放提取的原文[/EXTRACTED_TEXT]
      [ANALYSIS]此处放诊断报告内容，请使用 Markdown 格式（多用标题和列表以增加可读性）[/ANALYSIS]
    `;

    try {
      const parts: any[] = [];
      if (attachment) {
        parts.push({ inlineData: { data: attachment.data, mimeType: attachment.mimeType } });
      }
      parts.push({ text: text || "请分析这份习作。" });

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: { parts },
        config: { 
          systemInstruction, 
          temperature: 0.7 
        }
      });

      const fullResponse = response.text || "";
      const extractedMatch = fullResponse.match(/\[EXTRACTED_TEXT\]([\s\S]*?)\[\/EXTRACTED_TEXT\]/);
      const analysisMatch = fullResponse.match(/\[ANALYSIS\]([\s\S]*?)\[\/ANALYSIS\]/);

      return {
        extractedText: extractedMatch ? extractedMatch[1].trim() : undefined,
        analysis: analysisMatch ? analysisMatch[1].trim() : fullResponse
      };
    } catch (error: any) {
      console.error("Gemini Analyze Error:", error);
      throw new Error(error.message || "分析服务暂不可用");
    }
  }

  async chat(message: string): Promise<string> {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: message,
        config: {
          systemInstruction: "你是一个名叫“语智笔”的 AI 助手。你说话幽默且专业，是学生们的良师益友。当被问及写作技巧时，请多引用名家名篇作为例子。",
        }
      });
      return response.text || "抱歉，刚才信号不太好。";
    } catch (error: any) {
      console.error("Gemini Chat Error:", error);
      return "对话服务暂时遇到了一点问题。";
    }
  }
}

