// 使用标准的导入方式，Vercel 会在部署时自动处理依赖
// @ts-ignore
import { createClient } from '@supabase/supabase-js';

export default async function handler(req: any, res: any) {
  if (req.method !== 'POST') return res.status(405).json({ message: 'Method not allowed' });

  const { code } = req.body;
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ success: false, message: '未授权访问' });
  }

  // 统一环境变量读取逻辑
  const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL || process.env.VITE_SUPABASE_URL || process.env.SUPABASE_URL;
  const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY;

  if (!supabaseUrl || !serviceKey) {
    return res.status(500).json({ success: false, message: '服务端配置缺失（请检查环境变量）' });
  }

  const token = authHeader.split(' ')[1];

  try {
    const supabaseAdmin = createClient(supabaseUrl, serviceKey);

    // 1. 验证用户令牌，确保请求合法
    const { data: { user }, error: authError } = await supabaseAdmin.auth.getUser(token);

    if (authError || !user) {
      return res.status(401).json({ success: false, message: '身份验证过期，请刷新页面重新操作' });
    }

    // 2. 检查激活码状态（区分大小写并过滤已使用）
    const normalizedCode = code.trim().toUpperCase();
    const { data: activation, error: codeError } = await supabaseAdmin
      .from('activation_codes')
      .select('*')
      .eq('code', normalizedCode)
      .eq('is_used', false)
      .single();

    if (codeError || !activation) {
      return res.status(400).json({ success: false, message: '激活码无效、不存在或已被使用' });
    }

    // 3. 原子化更新：更新用户等级并作废激活码
    const { error: updateError } = await supabaseAdmin
      .from('profiles')
      .update({ 
        tier: activation.tier, 
        updated_at: new Date().toISOString() 
      })
      .eq('id', user.id);

    if (updateError) throw updateError;

    const { error: codeUpdateError } = await supabaseAdmin
      .from('activation_codes')
      .update({ 
        is_used: true, 
        used_by: user.id, 
        used_at: new Date().toISOString() 
      })
      .eq('code', normalizedCode);

    if (codeUpdateError) throw codeUpdateError;

    return res.status(200).json({ 
      success: true, 
      message: `恭喜！已成功激活 ${activation.tier.toUpperCase()} 会员特权。` 
    });
  } catch (err: any) {
    console.error('Activation critical error:', err);
    return res.status(500).json({ success: false, message: '激活过程中发生系统错误，请联系管理员' });
  }
}

