import { createClient } from '@supabase/supabase-js';

export default async function handler(req: any, res: any) {
  if (req.method !== 'POST') return res.status(405).json({ message: 'Method not allowed' });

  const authHeader = req.headers.authorization;
  if (!authHeader) return res.status(401).json({ message: '未授权' });

  const { tier, count = 1 } = req.body;

  const supabaseUrl = process.env.SUPABASE_URL || process.env.VITE_SUPABASE_URL;
  const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
  const supabaseAdmin = createClient(supabaseUrl!, serviceKey!);

  try {
    // 1. 验证调用者是否具有管理员权限 (这里可以检查用户 ID 或 Role)
    const token = authHeader.split(' ')[1];
    const { data: { user }, error: authError } = await supabaseAdmin.auth.getUser(token);

    // 这里简单硬编码管理员邮箱，实际生产中应在 profiles 表中增加 role 字段
    const ADMIN_EMAILS = ['admin@example.com', 'soralabe@foxmail.com']; 
    if (authError || !user || !ADMIN_EMAILS.includes(user.email || '')) {
      return res.status(403).json({ message: '权限不足' });
    }

    // 2. 生成激活码
    const codes = [];
    for (let i = 0; i < count; i++) {
      const code = Math.random().toString(36).substring(2, 10).toUpperCase();
      codes.push({
        code,
        tier,
        is_used: false,
        created_at: new Date().toISOString()
      });
    }

    const { data, error } = await supabaseAdmin
      .from('activation_codes')
      .insert(codes)
      .select();

    if (error) throw error;

    return res.status(200).json({ success: true, codes: data });
  } catch (err: any) {
    return res.status(500).json({ success: false, message: err.message });
  }
}

import React, { useState } from 'react';
import { ShieldCheck, Copy, Check, Loader2, Plus, Zap } from 'lucide-react';
import { supabase } from '../services/supabaseClient';

const AdminPanel: React.FC = () => {
  const [tier, setTier] = useState<'pro' | 'plus'>('pro');
  const [count, setCount] = useState(1);
  const [isGenerating, setIsGenerating] = useState(false);
  const [newCodes, setNewCodes] = useState<any[]>([]);
  const [copiedIndex, setCopiedIndex] = useState<number | null>(null);

  const generateCodes = async () => {
    setIsGenerating(true);
    try {
      const { data: { session } } = await supabase!.auth.getSession();
      const response = await fetch('/api/admin/generate', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${session?.access_token}`
        },
        body: JSON.stringify({ tier, count })
      });
      const result = await response.json();
      if (result.success) {
        setNewCodes(result.codes);
      } else {
        alert(result.message);
      }
    } catch (err) {
      alert("生成失败");
    } finally {
      setIsGenerating(false);
    }
  };

  const copyToClipboard = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopiedIndex(index);
    setTimeout(() => setCopiedIndex(null), 2000);
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center space-x-3 mb-4">
        <ShieldCheck className="text-red-500" />
        <h2 className="text-xl font-bold text-white">管理员分权中心</h2>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div className="space-y-2">
          <label className="text-xs font-bold text-slate-500 uppercase">会员等级</label>
          <div className="flex bg-slate-900 rounded-xl p-1 border border-slate-800">
            <button 
              onClick={() => setTier('pro')}
              className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${tier === 'pro' ? 'bg-red-600 text-white' : 'text-slate-400 hover:text-white'}`}
            >精进版 (PRO)</button>
            <button 
              onClick={() => setTier('plus')}
              className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${tier === 'plus' ? 'bg-red-600 text-white' : 'text-slate-400 hover:text-white'}`}
            >全能版 (PLUS)</button>
          </div>
        </div>
        <div className="space-y-2">
          <label className="text-xs font-bold text-slate-500 uppercase">生成数量</label>
          <input 
            type="number" 
            min="1" max="50"
            value={count}
            onChange={(e) => setCount(parseInt(e.target.value))}
            className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-2.5 text-sm text-white focus:outline-none focus:border-red-500"
          />
        </div>
      </div>

      <button 
        onClick={generateCodes}
        disabled={isGenerating}
        className="w-full py-3 bg-white text-black font-bold rounded-xl hover:bg-slate-200 transition-all flex items-center justify-center space-x-2 shadow-xl shadow-white/5 disabled:opacity-50"
      >
        {isGenerating ? <Loader2 className="animate-spin" size={18} /> : <Zap size={18} />}
        <span>一键生成激活码</span>
      </button>

      {newCodes.length > 0 && (
        <div className="mt-8 space-y-3 max-h-60 overflow-y-auto pr-2 scroll-custom">
          {newCodes.map((item, idx) => (
            <div key={idx} className="flex items-center justify-between p-4 bg-slate-900/50 border border-slate-800 rounded-2xl group hover:border-red-500/30 transition-all">
              <div>
                <span className="text-xs font-mono font-bold text-red-400 mr-3">{item.code}</span>
                <span className="text-[10px] bg-slate-800 text-slate-400 px-2 py-0.5 rounded uppercase">{item.tier}</span>
              </div>
              <button 
                onClick={() => copyToClipboard(item.code, idx)}
                className="text-slate-500 hover:text-white transition-colors"
              >
                {copiedIndex === idx ? <Check size={16} className="text-green-500" /> : <Copy size={16} />}
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

