import { User } from '../types.ts';
import { supabase } from './supabaseClient.ts';

class AuthService {
  async getCurrentUser(): Promise<User> {
    if (!supabase) return this.getMockUser();

    try {
      // Fix: Accessing getSession on any to avoid Supabase type mismatch
      const { data: sessionData, error: sessionError } = await (supabase.auth as any).getSession();
      if (sessionError || !sessionData?.session?.user) {
        return this.getMockUser();
      }

      const user = sessionData.session.user;
      const { data: profile, error: profileError } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', user.id)
        .single();

      if (profileError || !profile) {
        return {
          id: user.id,
          email: user.email,
          tier: 'free',
          dailyCount: 0
        };
      }

      return {
        id: user.id,
        email: user.email,
        tier: profile.tier || 'free',
        dailyCount: profile.daily_count || 0
      };
    } catch (e) {
      console.warn("Supabase auth error, falling back to mock:", e);
      return this.getMockUser();
    }
  }

  async activate(code: string): Promise<{ success: boolean; message: string }> {
    if (!supabase) return { success: false, message: '数据库未连接' };

    try {
      // Fix: Accessing getSession on any to avoid Supabase type mismatch
      const { data: { session } } = await (supabase.auth as any).getSession();
      if (!session) return { success: false, message: '请先登录' };

      const response = await fetch('/api/activate', {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${session.access_token}`
        },
        body: JSON.stringify({ code })
      });

      return await response.json();
    } catch (error) {
      return { success: false, message: '激活请求失败' };
    }
  }

  getMockUser(): User {
    // 强制返回 PLUS 权限，确保 OCR 功能默认开启
    return { 
      id: 'LOCAL-TESTER', 
      tier: 'plus', 
      dailyCount: 10 
    };
  }

  async signInAnonymously() {
    if (!supabase) return { data: null, error: new Error("Supabase not initialized") };
    try {
      // Fix: Accessing signInAnonymously on any to avoid Supabase type mismatch
      return await (supabase.auth as any).signInAnonymously();
    } catch (e) {
      return { data: null, error: e };
    }
  }
}

export const authService = new AuthService();

// @ts-ignore
import { createClient } from '@supabase/supabase-js';

export default async function handler(req: any, res: any) {
  if (req.method !== 'POST') return res.status(405).json({ message: 'Method not allowed' });

  const { code } = req.body;
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ success: false, message: '未授权访问' });
  }

  const supabaseUrl = process.env.SUPABASE_URL || process.env.VITE_SUPABASE_URL;
  const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
  const token = authHeader.split(' ')[1];

  try {
    const supabaseAdmin = createClient(supabaseUrl!, serviceKey!);
    // Fix: Use any cast to bypass SupabaseAuthClient type mismatch for getUser
    const { data: { user }, error: authError } = await (supabaseAdmin.auth as any).getUser(token);

    if (authError || !user) {
      return res.status(401).json({ success: false, message: '身份验证过期' });
    }

    // 1. 安全检查：检查该用户近期的失败尝试次数
    const { data: profile } = await supabaseAdmin
      .from('profiles')
      .select('failed_attempts, last_attempt_at')
      .eq('id', user.id)
      .single();

    if (profile && profile.failed_attempts >= 5) {
      const lastAttempt = new Date(profile.last_attempt_at).getTime();
      const now = new Date().getTime();
      if (now - lastAttempt < 3600000) { // 1小时限制
        return res.status(429).json({ success: false, message: '尝试次数过多，请1小时后再试' });
      }
    }

    // 2. 验证激活码
    const normalizedCode = code.trim().toUpperCase();
    const { data: activation, error: codeError } = await supabaseAdmin
      .from('activation_codes')
      .select('*')
      .eq('code', normalizedCode)
      .eq('is_used', false)
      .single();

    if (codeError || !activation) {
      // 增加失败计数
      await supabaseAdmin.from('profiles').update({
        failed_attempts: (profile?.failed_attempts || 0) + 1,
        last_attempt_at: new Date().toISOString()
      }).eq('id', user.id);

      return res.status(400).json({ success: false, message: '激活码无效或已被使用' });
    }

    // 3. 激活成功：清空失败计数并更新权限
    const { error: updateError } = await supabaseAdmin
      .from('profiles')
      .update({ 
        tier: activation.tier, 
        failed_attempts: 0,
        updated_at: new Date().toISOString() 
      })
      .eq('id', user.id);

    if (updateError) throw updateError;

    await supabaseAdmin
      .from('activation_codes')
      .update({ 
        is_used: true, 
        used_by: user.id, 
        used_at: new Date().toISOString() 
      })
      .eq('code', normalizedCode);

    return res.status(200).json({ 
      success: true, 
      message: `激活成功！您现在是 ${activation.tier.toUpperCase()} 会员。` 
    });
  } catch (err: any) {
    return res.status(500).json({ success: false, message: '系统错误' });
  }
}

