import { createClient } from '@supabase/supabase-js';

export default async function handler(req: any, res: any) {
  if (req.method !== 'POST') return res.status(405).json({ message: 'Method not allowed' });

  const authHeader = req.headers.authorization;
  const supabaseUrl = process.env.SUPABASE_URL || process.env.VITE_SUPABASE_URL;
  const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY;

  if (!authHeader || !serviceKey) return res.status(401).json({ message: '未授权配置' });

  try {
    const supabaseAdmin = createClient(supabaseUrl!, serviceKey);
    const token = authHeader.split(' ')[1];
    // Fix: Use any cast to bypass SupabaseAuthClient type mismatch for getUser
    const { data: { user }, error: authError } = await (supabaseAdmin.auth as any).getUser(token);

    // 管理员硬白名单
    const ADMIN_EMAILS = ['admin@example.com', 'soralabe@foxmail.com']; 
    if (authError || !user || !ADMIN_EMAILS.includes(user.email || '')) {
      return res.status(403).json({ message: '您没有管理员权限' });
    }

    const { tier, count = 1 } = req.body;
    const codes = [];

    // 使用更强的随机数生成
    const crypto = require('crypto');
    for (let i = 0; i < count; i++) {
      const code = crypto.randomBytes(4).toString('hex').toUpperCase();
      codes.push({
        code,
        tier,
        is_used: false,
        created_at: new Date().toISOString()
      });
    }

    const { data, error } = await supabaseAdmin
      .from('activation_codes')
      .insert(codes)
      .select();

    if (error) throw error;

    return res.status(200).json({ success: true, codes: data });
  } catch (err: any) {
    return res.status(500).json({ success: false, message: '生成失败' });
  }
}

