  const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY;

  if (!authHeader || !serviceKey || !supabaseUrl) {
    return res.status(401).json({ message: '服务端鉴权配置缺失' });
  }

  try {
    const supabaseAdmin = createClient(supabaseUrl, serviceKey);
    const token = authHeader.split(' ')[1];
    const { data: { user }, error: authError } = await (supabaseAdmin.auth as any).getUser(token);

    const ADMIN_EMAILS = ['admin@example.com', 'soralabe@foxmail.com']; 
    if (authError || !user || !ADMIN_EMAILS.includes(user.email || '')) {
      return res.status(403).json({ message: '禁止访问：非管理员身份' });
    }

    const { tier, count = 1 } = req.body;
    const codes = [];

    // Fix: Moved crypto usage to rely on top-level ESM import to resolve 'Cannot find name require'
    for (let i = 0; i < count; i++) {
      const code = crypto.randomBytes(4).toString('hex').toUpperCase();
      codes.push({
        code,
        tier,
        is_used: false,
        created_at: new Date().toISOString()
      });
    }

    const { data, error } = await supabaseAdmin.from('activation_codes').insert(codes).select();
    if (error) throw error;

    return res.status(200).json({ success: true, codes: data });
  } catch (err: any) {
    return res.status(500).json({ success: false, message: '生成激活码失败' });
  }
}

