    const contents = [{
      role: 'user',
      parts: [
        ...(attachment ? [{ inlineData: { data: attachment.data, mimeType: attachment.mimeType } }] : []),
        { text: message || "请分析这份习作。" }
      ]
    }];

    const response = await ai.models.generateContent({
      model: modelName,
      contents: contents,
      config: {
        systemInstruction: systemInstruction || "你是一个友好的 AI 助手。",
        responseMimeType: type === 'analyze' ? "application/json" : "text/plain",
      },
    });

