import crypto from 'node:crypto';
// @ts-ignore
import { createClient } from '@supabase/supabase-js';

export default async function handler(req: any, res: any) {
  if (req.method !== 'POST') return res.status(405).json({ message: 'Method not allowed' });

  const { username, password } = req.body;
  const authHeader = req.headers.authorization;

  const supabaseUrl = process.env.SUPABASE_URL;
  const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY;

  if (!authHeader || !supabaseUrl || !serviceKey) {
    return res.status(401).json({ message: '鉴权配置不完整' });
  }

  try {
    const supabaseAdmin = createClient(supabaseUrl, serviceKey);
    const token = authHeader.split(' ')[1];

    // 1. 第一层防御：验证 Supabase 邮箱是否在管理员白名单
    const { data: { user } } = await (supabaseAdmin.auth as any).getUser(token);
    const ADMIN_EMAILS = ['admin@example.com', 'soralabe@foxmail.com'];
    if (!user || !ADMIN_EMAILS.includes(user.email || '')) {
      return res.status(403).json({ message: '拒绝访问：无权限' });
    }

    // 2. 第二层防御：查询数据库中的管理员账号
    // 提示：你需要先在数据库 admin_credentials 表中插入对应的用户名、哈希和盐值
    const { data: adminData, error: dbError } = await supabaseAdmin
      .from('admin_credentials')
      .select('*')
      .eq('username', username)
      .single();

    if (dbError || !adminData) {
      return res.status(401).json({ success: false, message: '管理员用户名不存在' });
    }

    // 3. 核心算法：使用 scrypt 进行哈希比对
    // 我们假设存储的 hash 是 base64 格式
    const derivedKey = crypto.scryptSync(password, adminData.salt, 64);
    const isValid = derivedKey.toString('hex') === adminData.password_hash;

    if (isValid) {
      // 验证通过，返回一个临时授权凭证（实际生产环境建议用 JWT）
      return res.status(200).json({ 
        success: true, 
        message: '二次验证通过',
        adminToken: crypto.randomBytes(32).toString('hex') 
      });
    } else {
      return res.status(401).json({ success: false, message: '密码校验失败' });
    }
  } catch (err) {
    return res.status(500).json({ success: false, message: '服务器内部错误' });
  }
}

