import crypto from 'node:crypto';
// @ts-ignore
import { createClient } from '@supabase/supabase-js';

export default async function handler(req: any, res: any) {
  if (req.method !== 'POST') return res.status(405).json({ message: 'Method not allowed' });

  const { username, password } = req.body;
  const authHeader = req.headers.authorization;

  const supabaseUrl = process.env.SUPABASE_URL;
  const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY;

  if (!authHeader || !supabaseUrl || !serviceKey) {
    return res.status(401).json({ message: '鉴权配置不完整' });
  }

  try {
    const supabaseAdmin = createClient(supabaseUrl, serviceKey);
    const token = authHeader.split(' ')[1];

    // 1. 第一层防御：验证 Supabase 邮箱是否在管理员白名单
    const { data: { user } } = await (supabaseAdmin.auth as any).getUser(token);
    const ADMIN_EMAILS = ['admin@example.com', 'soralabe@foxmail.com'];
    if (!user || !ADMIN_EMAILS.includes(user.email || '')) {
      return res.status(403).json({ message: '拒绝访问：无权限' });
    }

    // 2. 第二层防御：查询数据库中的管理员账号
    const { data: adminData, error: dbError } = await supabaseAdmin
      .from('admin_credentials')
      .select('*')
      .eq('username', username)
      .single();

    if (dbError || !adminData) {
      return res.status(401).json({ success: false, message: '管理员用户名不存在' });
    }

    // 3. 核心算法：使用 scrypt 进行哈希比对
    // 默认使用 Node.js 的加密标准，存储和比对均为 hex 十六进制字符串
    const derivedKey = crypto.scryptSync(password, adminData.salt, 64);
    const isValid = derivedKey.toString('hex') === adminData.password_hash;

    if (isValid) {
      return res.status(200).json({ 
        success: true, 
        message: '二次验证通过',
        adminToken: crypto.randomBytes(32).toString('hex') 
      });
    } else {
      return res.status(401).json({ success: false, message: '密码校验失败' });
    }
  } catch (err) {
    return res.status(500).json({ success: false, message: '服务器内部错误' });
  }
}

import { AnalysisResult } from "../types";

export class GeminiService {
  private async callProxy(payload: any) {
    const response = await fetch('/api/ai', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });

    if (!response.ok) {
      const err = await response.json();
      throw new Error(err.error || "请求失败");
    }

    return await response.json();
  }

  async analyzeWriting(text: string, attachment?: { data: string; mimeType: string }): Promise<AnalysisResult> {
    const data = await this.callProxy({
      type: 'analyze',
      message: text,
      attachment,
      systemInstruction: `
        你是一名资深语文特级教师。请对学生习作进行深度诊断。
        必须严格按以下纯 JSON 格式输出结果，不要包含任何 markdown 标签或多余文字：
        {
          "extractedText": "如果是图片，请提取完整文字；如果是文本，留空",
          "scores": {"language": 80, "logic": 80, "structure": 80, "style": 80, "creativity": 80},
          "mainAnalysis": "评价内容",
          "brightSpots": ["亮点"],
          "suggestions": ["建议"]
        }
      `
    });

    try {
      // 增强型解析：去除可能存在的 ```json ... ``` 标签
      let cleanText = data.text || '{}';
      cleanText = cleanText.replace(/```json/g, '').replace(/```/g, '').trim();

      const result = JSON.parse(cleanText);
      return {
        extractedText: result.extractedText || undefined,
        scores: result.scores || { language: 0, logic: 0, structure: 0, style: 0, creativity: 0 },
        mainAnalysis: result.mainAnalysis || "分析完成",
        suggestions: result.suggestions || [],
        brightSpots: result.brightSpots || []
      };
    } catch (e) {
      console.error("AI Response Parsing Failed:", data.text);
      throw new Error("AI 返回数据格式异常，请稍后重试");
    }
  }

  async chat(message: string): Promise<string> {
    try {
      const data = await this.callProxy({
        type: 'chat',
        message: message,
        systemInstruction: "你是一个名叫“语智笔”的 AI 助手。你说话幽默且专业，是学生们的良师益友。"
      });
      return data.text || "抱歉，刚才信号不太好。";
    } catch (error: any) {
      return `对话服务异常：${error.message}。请联系管理员检查后端配置。`;
    }
  }
}

