import { GoogleGenAI } from "@google/genai";

export default async function handler(req: any, res: any) {
  if (req.method !== 'POST') return res.status(405).json({ message: 'Method not allowed' });

  const { type, message, attachment, systemInstruction } = req.body;
  const apiKey = process.env.API_KEY;

  if (!apiKey) {
    return res.status(500).json({ error: "服务器未配置 API_KEY，请在托管平台后台设置。" });
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    // 统一使用更稳定且快速的 flash 模型进行分析
    const modelName = 'gemini-3-flash-preview';

    const contents = [{
      role: 'user',
      parts: [
        ...(attachment ? [{ inlineData: { data: attachment.data, mimeType: attachment.mimeType } }] : []),
        { text: message || "请分析这份习作。" }
      ]
    }];

    const response = await ai.models.generateContent({
      model: modelName,
      contents: contents,
      config: {
        systemInstruction: systemInstruction || "你是一个友好的 AI 助手。",
        responseMimeType: type === 'analyze' ? "application/json" : "text/plain",
      },
    });

    return res.status(200).json({ text: response.text });
  } catch (error: any) {
    console.error("Gemini API Proxy Error:", error);
    return res.status(500).json({ error: error.message || "AI 响应超时或请求失败" });
  }
}

import { User } from '../types.ts';
import { supabase } from './supabaseClient.ts';

class AuthService {
  async getCurrentUser(): Promise<User> {
    if (!supabase) return this.getMockUser();

    try {
      const { data: sessionData, error: sessionError } = await (supabase.auth as any).getSession();
      if (sessionError || !sessionData?.session?.user) {
        return this.getMockUser();
      }

      const user = sessionData.session.user;
      const { data: profile, error: profileError } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', user.id)
        .single();

      if (profileError || !profile) {
        return {
          id: user.id,
          email: user.email,
          tier: 'free',
          dailyCount: 0
        };
      }

      return {
        id: user.id,
        email: user.email,
        tier: profile.tier || 'free',
        dailyCount: profile.daily_count || 0
      };
    } catch (e) {
      console.warn("Supabase auth error, falling back to mock:", e);
      return this.getMockUser();
    }
  }

  async signIn(email: string): Promise<{ error: any }> {
    if (!supabase) return { error: new Error("数据库未连接") };
    // Supabase 默认会发送包含 Link 和 Code 的邮件
    return await (supabase.auth as any).signInWithOtp({ 
      email,
      options: {
        shouldCreateUser: true,
        emailRedirectTo: window.location.origin
      }
    });
  }

  async verifyOtp(email: string, token: string): Promise<{ error: any }> {
    if (!supabase) return { error: new Error("数据库未连接") };
    return await (supabase.auth as any).verifyOtp({
      email,
      token,
      type: 'magiclink' // Supabase 的 magiclink 邮件中包含的 6 位码通常属于此类型或 'signup'
    });
  }

  async signOut() {
    if (!supabase) return;
    await (supabase.auth as any).signOut();
    window.location.reload();
  }

  async activate(code: string): Promise<{ success: boolean; message: string }> {
    if (!supabase) return { success: false, message: '数据库未连接' };

    try {
      const { data: { session } } = await (supabase.auth as any).getSession();
      if (!session) return { success: false, message: '请先登录' };

      const response = await fetch('/api/activate', {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${session.access_token}`
        },
        body: JSON.stringify({ code })
      });

      return await response.json();
    } catch (error) {
      return { success: false, message: '激活请求失败' };
    }
  }

  getMockUser(): User {
    return { 
      id: 'GUEST-USER', 
      tier: 'free', 
      dailyCount: 0 
    };
  }
}

