import { GoogleGenAI } from "@google/genai";

export async function onRequest(context: any) {
  const { request, env } = context;

  if (request.method !== 'POST') {
    return new Response(JSON.stringify({ message: 'Method not allowed' }), { status: 405 });
  }

  const apiKey = env.API_KEY;
  if (!apiKey) {
    return new Response(JSON.stringify({ error: "服务器未配置 API_KEY" }), { status: 500 });
  }

  try {
    const body: any = await request.json();
    const { type, message, attachment, systemInstruction } = body;

    const ai = new GoogleGenAI({ apiKey });
    const modelName = 'gemini-3-flash-preview';

    const contents = [{
      role: 'user',
      parts: [
        ...(attachment ? [{ inlineData: { data: attachment.data, mimeType: attachment.mimeType } }] : []),
        { text: message || "请分析这份习作。" }
      ]
    }];

    const response = await ai.models.generateContent({
      model: modelName,
      contents: contents,
      config: {
        systemInstruction: systemInstruction || "你是一个友好的 AI 助手。",
        responseMimeType: type === 'analyze' ? "application/json" : "text/plain",
      },
    });

    return new Response(JSON.stringify({ text: response.text }), {
      headers: { 'Content-Type': 'application/json' }
    });
  } catch (error: any) {
    return new Response(JSON.stringify({ error: error.message || "AI 响应异常" }), { status: 500 });
  }
}

import { createClient } from '@supabase/supabase-js';

export async function onRequest(context: any) {
  const { request, env } = context;
  if (request.method !== 'POST') return new Response('Method not allowed', { status: 405 });

  const { code } = await request.json();
  const authHeader = request.headers.get('authorization');

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return new Response(JSON.stringify({ success: false, message: '未授权访问' }), { status: 401 });
  }

  const supabaseUrl = env.SUPABASE_URL;
  const serviceKey = env.SUPABASE_SERVICE_ROLE_KEY;
  const token = authHeader.split(' ')[1];

  if (!supabaseUrl || !serviceKey) {
    return new Response(JSON.stringify({ success: false, message: '环境配置缺失' }), { status: 500 });
  }

  try {
    const supabaseAdmin = createClient(supabaseUrl, serviceKey);
    const { data: { user }, error: authError } = await (supabaseAdmin.auth as any).getUser(token);

    if (authError || !user) {
      return new Response(JSON.stringify({ success: false, message: '身份验证过期' }), { status: 401 });
    }

    const normalizedCode = code.trim().toUpperCase();
    const { data: activation, error: codeError } = await supabaseAdmin
      .from('activation_codes')
      .select('*')
      .eq('code', normalizedCode)
      .eq('is_used', false)
      .single();

    if (codeError || !activation) {
      return new Response(JSON.stringify({ success: false, message: '激活码无效' }), { status: 400 });
    }

    await supabaseAdmin.from('profiles').update({ tier: activation.tier }).eq('id', user.id);
    await supabaseAdmin.from('activation_codes').update({ 
      is_used: true, 
      used_by: user.id,
      used_at: new Date().toISOString() 
    }).eq('code', normalizedCode);

    return new Response(JSON.stringify({ success: true, message: '激活成功' }), {
      headers: { 'Content-Type': 'application/json' }
    });
  } catch (err: any) {
    return new Response(JSON.stringify({ success: false, message: '系统错误' }), { status: 500 });
  }
}

import { AnalysisResult } from "../types";

export class GeminiService {
  private async callProxy(payload: any) {
    // 路径保持不变，Cloudflare Pages 会自动匹配 /functions/api/*.ts 为 /api/*
    const response = await fetch('/api/ai', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });

    if (!response.ok) {
      const err = await response.json();
      throw new Error(err.error || "请求失败");
    }

    return await response.json();
  }

  async analyzeWriting(text: string, attachment?: { data: string; mimeType: string }): Promise<AnalysisResult> {
    const data = await this.callProxy({
      type: 'analyze',
      message: text,
      attachment,
      systemInstruction: `
        你是一名资深语文特级教师。请对学生习作进行深度诊断。
        必须严格按以下纯 JSON 格式输出结果，不要包含任何 markdown 标签或多余文字：
        {
          "extractedText": "如果是图片，请提取完整文字；如果是文本，留空",
          "scores": {"language": 80, "logic": 80, "structure": 80, "style": 80, "creativity": 80},
          "mainAnalysis": "评价内容",
          "brightSpots": ["亮点"],
          "suggestions": ["建议"]
        }
      `
    });

    try {
      let cleanText = data.text || '{}';
      cleanText = cleanText.replace(/```json/g, '').replace(/```/g, '').trim();

      const result = JSON.parse(cleanText);
      return {
        extractedText: result.extractedText || undefined,
        scores: result.scores || { language: 0, logic: 0, structure: 0, style: 0, creativity: 0 },
        mainAnalysis: result.mainAnalysis || "分析完成",
        suggestions: result.suggestions || [],
        brightSpots: result.brightSpots || []
      };
    } catch (e) {
      throw new Error("AI 返回数据格式异常，请稍后重试");
    }
  }

  async chat(message: string): Promise<string> {
    try {
      const data = await this.callProxy({
        type: 'chat',
        message: message,
        systemInstruction: "你是一个名叫“语智笔”的 AI 助手。你说话幽默且专业，是学生们的良师益友。"
      });
      return data.text || "抱歉，刚才信号不太好。";
    } catch (error: any) {
      return `对话服务异常：${error.message}`;
    }
  }
}

