import { createClient } from '@supabase/supabase-js';

export async function onRequest(context: any) {
  const { request, env } = context;
  if (request.method !== 'POST') return new Response('Method not allowed', { status: 405 });

  const { username, password } = await request.json();
  const authHeader = request.headers.get('authorization');

  const supabaseUrl = env.SUPABASE_URL;
  const serviceKey = env.SUPABASE_SERVICE_ROLE_KEY;

  if (!authHeader || !supabaseUrl || !serviceKey) {
    return new Response(JSON.stringify({ message: '鉴权配置不完整' }), { status: 401 });
  }

  try {
    const supabaseAdmin = createClient(supabaseUrl, serviceKey);
    const token = authHeader.split(' ')[1];

    // 1. 验证 Supabase 会话
    const { data: { user } } = await (supabaseAdmin.auth as any).getUser(token);
    const ADMIN_EMAILS = ['admin@example.com', 'soralabe@foxmail.com'];
    if (!user || !ADMIN_EMAILS.includes(user.email || '')) {
      return new Response(JSON.stringify({ message: '拒绝访问：无权限' }), { status: 403 });
    }

    // 2. 查询管理员账号
    const { data: adminData, error: dbError } = await supabaseAdmin
      .from('admin_credentials')
      .select('*')
      .eq('username', username)
      .single();

    if (dbError || !adminData) {
      return new Response(JSON.stringify({ success: false, message: '管理员不存在' }), { status: 401 });
    }

    // 3. 密码比对 
    // 注意：在 CF Pages 中建议开启 nodejs_compat 标志以支持 crypto
    // 或者此处根据你的数据库存储格式进行调整
    // 为了极致兼容性，这里假设你已开启兼容标志
    const crypto = require('node:crypto');
    const derivedKey = crypto.scryptSync(password, adminData.salt, 64);
    const isValid = derivedKey.toString('hex') === adminData.password_hash;

    if (isValid) {
      return new Response(JSON.stringify({ 
        success: true, 
        message: '二次验证通过'
      }), { headers: { 'Content-Type': 'application/json' } });
    } else {
      return new Response(JSON.stringify({ success: false, message: '密码错误' }), { status: 401 });
    }
  } catch (err: any) {
    return new Response(JSON.stringify({ success: false, message: '服务器错误: ' + err.message }), { status: 500 });
  }
}

import { createClient } from '@supabase/supabase-js';

export async function onRequest(context: any) {
  const { request, env } = context;
  if (request.method !== 'POST') return new Response('Method not allowed', { status: 405 });

  const authHeader = request.headers.get('authorization');
  const supabaseUrl = env.SUPABASE_URL;
  const serviceKey = env.SUPABASE_SERVICE_ROLE_KEY;

  if (!authHeader || !serviceKey || !supabaseUrl) {
    return new Response(JSON.stringify({ message: '配置缺失' }), { status: 401 });
  }

  try {
    const supabaseAdmin = createClient(supabaseUrl, serviceKey);
    const token = authHeader.split(' ')[1];
    const { data: { user } } = await (supabaseAdmin.auth as any).getUser(token);

    const ADMIN_EMAILS = ['admin@example.com', 'soralabe@foxmail.com']; 
    if (!user || !ADMIN_EMAILS.includes(user.email || '')) {
      return new Response(JSON.stringify({ message: '无权操作' }), { status: 403 });
    }

    const { tier, count = 1 } = await request.json();
    const codes = [];

    // 使用 Web Crypto 生成随机码，兼容性更好
    for (let i = 0; i < count; i++) {
      const array = new Uint8Array(4);
      crypto.getRandomValues(array);
      const code = Array.from(array, byte => byte.toString(16).padStart(2, '0')).join('').toUpperCase();

      codes.push({
        code,
        tier,
        is_used: false,
        created_at: new Date().toISOString()
      });
    }

    const { data, error } = await supabaseAdmin.from('activation_codes').insert(codes).select();
    if (error) throw error;

    return new Response(JSON.stringify({ success: true, codes: data }), {
      headers: { 'Content-Type': 'application/json' }
    });
  } catch (err: any) {
    return new Response(JSON.stringify({ success: false, message: '生成失败: ' + err.message }), { status: 500 });
  }
}

