import { GoogleGenAI } from "@google/genai";

export default async function handler(req: any, res: any) {
  if (req.method !== 'POST') return res.status(405).json({ message: 'Method not allowed' });

  const { type, message, attachment, systemInstruction } = req.body;

  // API key must be obtained exclusively from the environment variable process.env.API_KEY.
  if (!process.env.API_KEY) {
    return res.status(500).json({ error: "服务器未配置 API_KEY，请在托管平台后台设置。" });
  }

  try {
    // Initialize GoogleGenAI with the API key from process.env.API_KEY.
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Using gemini-3-pro-preview for complex writing analysis and reasoning.
    const modelName = 'gemini-3-pro-preview';

    // Constructing contents as a parts object to support multimodal inputs correctly.
    const contents = {
      parts: [
        ...(attachment ? [{ inlineData: { data: attachment.data, mimeType: attachment.mimeType } }] : []),
        { text: message || "请分析这份习作。" }
      ]
    };

    const response = await ai.models.generateContent({
      model: modelName,
      contents: contents,
      config: {
        systemInstruction: systemInstruction || "你是一个友好的 AI 助手。",
        responseMimeType: type === 'analyze' ? "application/json" : "text/plain",
      },
    });

    // Access the .text property directly from the response object.
    return res.status(200).json({ text: response.text });
  } catch (error: any) {
    console.error("Gemini API Proxy Error:", error);
    return res.status(500).json({ error: error.message || "AI 响应超时或请求失败" });
  }
}

import { GoogleGenAI } from "@google/genai";

export async function onRequest(context: any) {
  const { request, env } = context;

  if (request.method !== 'POST') {
    return new Response(JSON.stringify({ message: 'Method not allowed' }), { status: 405 });
  }

  // Use the API_KEY provided in the environment context.
  const apiKey = env.API_KEY;
  if (!apiKey) {
    return new Response(JSON.stringify({ error: "服务器未配置 API_KEY" }), { status: 500 });
  }

  try {
    const body: any = await request.json();
    const { type, message, attachment, systemInstruction } = body;

    // Initialize the AI client using the provided API key.
    const ai = new GoogleGenAI({ apiKey });

    // Using gemini-3-pro-preview for complex writing analysis tasks.
    const modelName = 'gemini-3-pro-preview';

    // Construct contents with parts for better support of multimodal inputs.
    const contents = {
      parts: [
        ...(attachment ? [{ inlineData: { data: attachment.data, mimeType: attachment.mimeType } }] : []),
        { text: message || "请分析这份习作。" }
      ]
    };

    const response = await ai.models.generateContent({
