import { GoogleGenAI } from "@google/genai";

export async function onRequest(context: any) {
  const { request, env } = context;

  if (request.method !== 'POST') {
    return new Response(JSON.stringify({ message: 'Method not allowed' }), { status: 405 });
  }

  const apiKey = env.API_KEY;
  if (!apiKey) {
    return new Response(JSON.stringify({ error: "服务器未配置 API_KEY" }), { status: 500 });
  }

  try {
    const body: any = await request.json();
    const { type, message, attachment, systemInstruction } = body;

    const ai = new GoogleGenAI({ apiKey });

    // 切换为 Flash 模型以避免 429 Quota Exceeded 错误
    // Flash 模型在免费层级拥有更高的并发限制和 Token 配额
    const modelName = 'gemini-3-flash-preview';

    const contents = {
      parts: [
        ...(attachment ? [{ inlineData: { data: attachment.data, mimeType: attachment.mimeType } }] : []),
        { text: message || "请分析这份习作。" }
      ]
    };

    const response = await ai.models.generateContent({
      model: modelName,
      contents: contents,
      config: {
        systemInstruction: systemInstruction || "你是一个友好的 AI 助手。",
        responseMimeType: type === 'analyze' ? "application/json" : "text/plain",
      },
    });

    return new Response(JSON.stringify({ text: response.text }), {
      headers: { 'Content-Type': 'application/json' }
    });
  } catch (error: any) {
    // 处理 429 错误，返回用户友好的提示
    const isQuotaExceeded = error.message?.includes('429') || error.message?.includes('RESOURCE_EXHAUSTED');
    const userFriendlyMessage = isQuotaExceeded 
      ? "AI 辅导员正在休息（配额已满），请 1 分钟后再尝试。" 
      : (error.message || "AI 响应异常");

    return new Response(JSON.stringify({ error: userFriendlyMessage }), { 
      status: isQuotaExceeded ? 429 : 500 
    });
  }
}

