  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [fileData, setFileData] = useState<{ data: string; mimeType: string; name: string } | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);
  const [downloading, setDownloading] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const canUpload = user.tier === 'plus' || user.tier === 'custom' || user.id === 'LOCAL-TESTER';

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!canUpload) {
      alert("附件识别为 Plus 会员专属功能。");
      return;
    }
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = (event.target?.result as string).split(',')[1];
      setFileData({ data: base64, mimeType: file.type, name: file.name });
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if ((!content.trim() && !fileData) || isAnalyzing) return;
    setIsAnalyzing(true);
    setAnalysis(null);
    setError(null);

    try {
      const result = await geminiService.analyzeWriting(content, fileData || undefined);
      if (result.extractedText) setContent(result.extractedText);
      setAnalysis(result);
    } catch (err: any) {
      setError(err.message || "分析失败，请检查配置。");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleCopy = () => {
    if (!analysis) return;
    const text = `【语智笔 AI 诊断报告】\n\n得分：\n语言: ${analysis.scores.language}\n逻辑: ${analysis.scores.logic}\n结构: ${analysis.scores.structure}\n文体: ${analysis.scores.style}\n创新: ${analysis.scores.creativity}\n\n总评：\n${analysis.mainAnalysis}\n\n亮点：\n${analysis.brightSpots.join('\n')}\n\n建议：\n${analysis.suggestions.join('\n')}`;
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
