              </div>
            )}

            <div className="relative flex-1 min-h-[500px] bg-slate-950/20">
              <textarea
                value={content}
                onChange={(e) => setContent(e.target.value)}
                placeholder="在此输入习作正文..."
                className="w-full h-full p-10 bg-transparent text-slate-200 resize-none focus:outline-none text-lg leading-relaxed placeholder:text-slate-800 scroll-custom"
              />
              <div className="absolute bottom-6 right-10 flex items-center space-x-4">
                <div className="text-[10px] text-slate-600 font-bold uppercase tracking-widest">{content.length} 字</div>
                <button 
                  onClick={handleAnalyze}
                  disabled={isAnalyzing || (!content.trim() && !fileData)}
                  className="flex items-center space-x-3 px-8 py-4 bg-red-600 hover:bg-red-700 disabled:bg-slate-800 text-white font-bold rounded-2xl shadow-xl shadow-red-600/20 transition-all active:scale-95"
                >
                  {isAnalyzing ? <Loader2 className="animate-spin" size={18} /> : <Sparkles size={18} />}
                  <span>{fileData ? '智能识别并分析' : '开始辅导'}</span>
                </button>
              </div>
            </div>
          </div>

          {/* 右侧：分析报告 */}
          <div className="flex flex-col space-y-6">
            {/* 评分看板 */}
            <div className="paper-card rounded-[2rem] border border-slate-800 p-8 shadow-xl">
              <div className="flex items-center justify-between mb-8">
                <div className="flex items-center space-x-2">
                  <BarChart3 className="text-red-400 w-5 h-5" />
                  <span className="font-bold text-slate-100">能力维度看板</span>
                </div>
                <div className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Writing Metrics</div>
              </div>

              <div className="space-y-2">
                <ScoreBar label="语言表达" score={analysis?.scores.language || 0} color="text-red-400" />
                <ScoreBar label="逻辑严密" score={analysis?.scores.logic || 0} color="text-orange-400" />
                <ScoreBar label="结构完整" score={analysis?.scores.structure || 0} color="text-amber-400" />
                <ScoreBar label="文体契合" score={analysis?.scores.style || 0} color="text-emerald-400" />
                <ScoreBar label="创新亮点" score={analysis?.scores.creativity || 0} color="text-blue-400" />
              </div>
            </div>

            {/* 详细诊断 */}
            <div className="flex-1 paper-card rounded-[2rem] border border-slate-800 overflow-hidden flex flex-col shadow-xl min-h-[400px]">
              <div className="px-8 py-5 bg-slate-900/40 border-b border-slate-800 flex items-center justify-between">
                <div className="flex items-center space-x-2 font-bold">
                  <ClipboardCheck className="text-emerald-400 w-5 h-5" />
                  <span className="text-slate-100">深度辅导意见</span>
                </div>
                {analysis && (
                  <div className="flex items-center space-x-2">
                    <button 
                      onClick={handleCopy} 
                      className="p-2 text-slate-500 hover:text-white hover:bg-slate-800 rounded-lg transition-all"
                      title="复制诊断报告"
                    >
                      {copied ? <Check size={16} className="text-emerald-400" /> : <Copy size={16} />}
                    </button>
                    <button 
                      onClick={handleDownload} 
                      disabled={downloading}
                      className="p-2 text-slate-500 hover:text-white hover:bg-slate-800 rounded-lg transition-all"
                      title="下载电子报告"
                    >
                      {downloading ? <Loader2 size={16} className="animate-spin text-red-400" /> : <Download size={16} />}
                    </button>
                  </div>
                )}
              </div>

              <div className="flex-1 overflow-y-auto p-8 space-y-6 scroll-custom relative">
                {isAnalyzing ? (
                  <div className="h-full flex flex-col items-center justify-center space-y-4 py-12">
                    <Loader2 className="animate-spin text-red-500 w-10 h-10" />
                    <p className="text-sm font-bold text-red-400 animate-pulse tracking-widest uppercase">AI 正在审阅稿件...</p>
                  </div>
                ) : error ? (
                  <div className="h-full flex flex-col items-center justify-center space-y-6 py-12 px-6 text-center animate-in fade-in zoom-in duration-300">
                    <div className="w-16 h-16 rounded-full bg-red-500/10 flex items-center justify-center text-red-500 border border-red-500/20">
                      <AlertCircle size={32} />
                    </div>
                    <div className="space-y-2">
                      <p className="text-red-400 font-bold">分析中断</p>
                      <p className="text-slate-500 text-xs leading-relaxed">{error}</p>
                    </div>
                    <button 
                      onClick={handleAnalyze}
                      className="px-6 py-2.5 bg-slate-900 hover:bg-slate-800 text-white text-xs font-bold rounded-xl border border-slate-800 flex items-center space-x-2 transition-all active:scale-95"
                    >
                      <RefreshCcw size={14} />
                      <span>重试分析</span>
                    </button>
                  </div>
                ) : analysis ? (
                  <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                    {/* 总评 */}
                    <div className="mb-8">
                      <div className="flex items-center space-x-2 text-slate-400 text-xs font-bold mb-3 uppercase tracking-wider">
                        <MessageSquareQuote size={14} className="text-red-400" />
                        <span>特级教师总评</span>
                      </div>
                      <p className="text-slate-300 leading-relaxed text-sm bg-slate-900/40 p-5 rounded-2xl border border-slate-800">
                        {analysis.mainAnalysis}
                      </p>
                    </div>

                    {/* 亮点 */}
                    <div className="mb-8">
                      <div className="flex items-center space-x-2 text-slate-400 text-xs font-bold mb-3 uppercase tracking-wider">
                        <Lightbulb size={14} className="text-emerald-400" />
                        <span>习作闪光点</span>
                      </div>
                      <div className="grid gap-3">
                        {analysis.brightSpots.map((spot, i) => (
                          <div key={i} className="flex items-start space-x-3 p-4 bg-emerald-500/5 rounded-xl border border-emerald-500/10 text-xs text-emerald-100/80">
                            <Check className="text-emerald-400 flex-shrink-0 mt-0.5" size={14} />
                            <span>{spot}</span>
                          </div>
                        ))}
                      </div>
                    </div>

                    {/* 建议 */}
                    <div>
                      <div className="flex items-center space-x-2 text-slate-400 text-xs font-bold mb-3 uppercase tracking-wider">
                        <AlertCircle size={14} className="text-orange-400" />
                        <span>过程性改进建议</span>
                      </div>
                      <div className="space-y-3">
                        {analysis.suggestions.map((sug, i) => (
                          <div key={i} className="group p-4 bg-orange-500/5 rounded-xl border border-orange-500/10 text-xs text-orange-100/80 hover:border-orange-500/30 transition-all">
                            <div className="flex items-center space-x-2 mb-2 font-bold text-orange-400/80">
                                <span>建议 {i+1}</span>
                                <ChevronRight size={12} className="group-hover:translate-x-1 transition-transform" />
                            </div>
                            <p>{sug}</p>
                          </div>
                        ))}
                      </div>
                    </div>
                  </div>
                ) : (
                  <div className="h-full flex flex-col items-center justify-center opacity-20 text-center px-10 py-12">
                    <BarChart3 size={48} className="mb-4 stroke-[1px]" />
                    <p className="text-sm font-medium">等待习作提交</p>
                    <p className="text-[10px] mt-2">完成后在此查看多维度评价与改进方案</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

