import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar.tsx';
import Hero from './components/Hero.tsx';
import Features from './components/Features.tsx';
import CompositionWorkspace from './components/CompositionWorkspace.tsx';
import AIChatPreview from './components/AIChatPreview.tsx';
import Pricing from './components/Pricing.tsx';
import Footer from './components/Footer.tsx';
import AdminPanel from './components/AdminPanel.tsx';
import { authService } from './services/authService.ts';
import { User } from './types.ts';
import { KeyRound, X, CheckCircle, Loader2, AlertTriangle, ShieldCheck, LogIn, LogOut, ArrowLeft, Mail, Link as LinkIcon, Command } from 'lucide-react';
import { supabase } from './services/supabaseClient.ts';

const App: React.FC = () => {
  const [user, setUser] = useState<User>(authService.getMockUser());
  const [loading, setLoading] = useState(true);
  const [showActivation, setShowActivation] = useState(false);
  const [showAdmin, setShowAdmin] = useState(false);
  const [showLogin, setShowLogin] = useState(false);

  const [loginStep, setLoginStep] = useState<'email' | 'verify'>('email');
  const [verifyMode, setVerifyMode] = useState<'link' | 'otp'>('link');
  const [email, setEmail] = useState('');
  const [otpCode, setOtpCode] = useState('');
  const [magicLink, setMagicLink] = useState('');

  const [activationCode, setActivationCode] = useState('');
  const [status, setStatus] = useState<{ type: 'success' | 'error' | null, msg: string }>({ type: null, msg: '' });

  // 更新管理员白名单
  const ADMIN_EMAILS = ['admin@example.com', 'soralabe@foxmail.com', 'yutongli895@gmail.com'];
  const isAdmin = user.email && ADMIN_EMAILS.includes(user.email);

  useEffect(() => {
    const initAuth = async () => {
      try {
        const currentUser = await authService.getCurrentUser();
        if (currentUser) setUser(currentUser);
      } finally {
        setLoading(false);
      }
    };
    initAuth();

    if (supabase) {
      const { data } = (supabase.auth as any).onAuthStateChange(async () => {
        const updatedUser = await authService.getCurrentUser();
        setUser(updatedUser);
      });
      return () => data.subscription.unsubscribe();
    }
  }, []);

  const handleSendOtp = async () => {
    if (!email) return;
    setStatus({ type: null, msg: '正在请求登录凭证...' });
    const { error } = await authService.signIn(email);
    if (error) {
      setStatus({ type: 'error', msg: error.message });
    } else {
      setLoginStep('verify');
      setStatus({ type: 'success', msg: '验证邮件已发送！请查收并在下方粘贴链接或输入数字。' });
    }
  };

  const handleVerifyLink = async () => {
    if (!magicLink) return;
    setStatus({ type: null, msg: '正在解析链接...' });
    const { error } = await authService.verifyLink(magicLink);
    if (error) {
      setStatus({ type: 'error', msg: '验证失败：' + error.message });
    } else {
      handleLoginSuccess();
    }
  };

  const handleVerifyOtp = async () => {
    if (!otpCode || otpCode.length < 6) return;
    setStatus({ type: null, msg: '正在验证...' });
    const { error } = await authService.verifyOtp(email, otpCode);
    if (error) {
      setStatus({ type: 'error', msg: '验证失败：码已失效或输入错误。' });
    } else {
      handleLoginSuccess();
    }
  };

  const handleLoginSuccess = async () => {
    setStatus({ type: 'success', msg: '登录成功！' });
    const updatedUser = await authService.getCurrentUser();
    setUser(updatedUser);
    setTimeout(() => setShowLogin(false), 1500);
  };

  const handleActivate = async () => {
    if (!activationCode) return;
    setStatus({ type: null, msg: '正在验证...' });
    const result = await authService.activate(activationCode);
    if (result.success) {
      const updatedUser = await authService.getCurrentUser();
      setUser(updatedUser);
      setStatus({ type: 'success', msg: result.message });
      setTimeout(() => setShowActivation(false), 2000);
    } else {
      setStatus({ type: 'error', msg: result.message });
    }
  };

  if (loading) return (
    <div className="min-h-screen bg-slate-950 flex items-center justify-center">
      <Loader2 className="animate-spin text-red-500" size={40} />
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 selection:bg-red-500 selection:text-white">
      <Navbar />
      <main>
        <div className="pt-28 px-6 max-w-7xl mx-auto flex flex-wrap gap-3 justify-end items-center">
          {isAdmin && (
            <button 
              onClick={() => { setShowActivation(true); setShowAdmin(true); }}
              className="flex items-center space-x-2 text-xs font-bold py-2.5 px-5 bg-red-600/10 border border-red-500/30 rounded-full hover:bg-red-600/20 transition-all text-red-400"
            >
              <ShieldCheck size={14} />
              <span>管理后台</span>
            </button>
          )}

          <div className="flex items-center bg-slate-900 border border-slate-800 rounded-full px-4 py-1.5 space-x-3 shadow-lg shadow-black/20">
             <div className="flex flex-col text-right">
                <span className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                  {user.email || '游客模式'}
                </span>
                <span className="text-[10px] text-red-400 font-bold">等级: {user.tier.toUpperCase()}</span>
             </div>
             {user.id === 'GUEST-USER' ? (
               <button onClick={() => { setShowLogin(true); setLoginStep('email'); setStatus({type: null, msg: ''}); }} className="p-1.5 hover:text-red-400 transition-colors"><LogIn size={16} /></button>
             ) : (
               <button onClick={() => authService.signOut()} className="p-1.5 hover:text-red-400 transition-colors"><LogOut size={16} /></button>
             )}
          </div>

          <button 
            onClick={() => { setShowActivation(true); setShowAdmin(false); setStatus({type: null, msg: ''}); }}
            className="flex items-center space-x-2 text-xs font-bold py-2.5 px-5 bg-slate-900 border border-slate-800 rounded-full hover:border-red-500 transition-all text-slate-400 hover:text-white"
          >
            <KeyRound size={14} className="text-red-400" />
            <span>输入激活码</span>
          </button>
        </div>

        <Hero />
        <Features />
        <div id="demo"><CompositionWorkspace user={user} /></div>
        <AIChatPreview />
        <Pricing />
      </main>
      <Footer />

      {(showActivation || showLogin) && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-950/80 backdrop-blur-sm">
          <div className="paper-card w-full max-w-lg p-10 rounded-[2.5rem] border border-slate-800 shadow-2xl relative">
            <button onClick={() => { setShowActivation(false); setShowLogin(false); }} className="absolute top-8 right-8 text-slate-500 hover:text-white transition-colors">
              <X size={24} />
            </button>

            {showLogin ? (
              <div className="animate-in fade-in slide-in-from-bottom-2">
                {loginStep === 'email' ? (
                  <>
                    <h3 className="text-3xl font-bold mb-2">身份识别</h3>
                    <p className="text-slate-400 text-sm mb-8">管理员请输入白名单邮箱。如邮件延迟或无法点击，可使用“复制链接”模式。</p>
                    <div className="space-y-4">
                      <div className="relative">
                        <Mail className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
                        <input 
                          type="email" 
                          value={email}
                          onChange={(e) => setEmail(e.target.value)}
                          placeholder="请输入邮箱地址"
                          className="w-full bg-slate-900 border border-slate-800 rounded-2xl pl-14 pr-6 py-4 focus:outline-none focus:border-red-500 text-white"
                        />
                      </div>
                      <button onClick={handleSendOtp} className="w-full py-4 bg-red-600 hover:bg-red-700 text-white font-bold rounded-2xl shadow-lg transition-all active:scale-95">
                        获取登录验证邮件
                      </button>

                      <div className="pt-4 border-t border-slate-800 flex justify-center">
                        <button 
                          onClick={() => { setShowAdmin(true); setShowLogin(false); }}
                          className="flex items-center space-x-2 text-[10px] font-bold text-slate-500 hover:text-red-400 transition-colors uppercase tracking-widest"
                        >
                          <Command size={12} />
                          <span>账号密码直通车 (需二次验证)</span>
                        </button>
                      </div>
                    </div>
                  </>
                ) : (
                  <>
                    <button onClick={() => setLoginStep('email')} className="flex items-center space-x-2 text-slate-500 hover:text-white mb-6 text-sm">
                      <ArrowLeft size={16} />
                      <span>返回修改邮箱</span>
                    </button>
                    <div className="flex items-center justify-between mb-2">
                      <h3 className="text-3xl font-bold">验证凭证</h3>
                      <div className="flex bg-slate-900 p-1 rounded-lg border border-slate-800">
                        <button onClick={() => setVerifyMode('link')} className={`px-3 py-1 text-[10px] font-bold rounded ${verifyMode === 'link' ? 'bg-red-600 text-white' : 'text-slate-500'}`}>链接模式</button>
                        <button onClick={() => setVerifyMode('otp')} className={`px-3 py-1 text-[10px] font-bold rounded ${verifyMode === 'otp' ? 'bg-red-600 text-white' : 'text-slate-500'}`}>验证码</button>
                      </div>
                    </div>
                    <p className="text-slate-400 text-sm mb-8">
                      {verifyMode === 'link' ? '请复制邮件中 Log In 按钮的完整链接并粘贴至下方。' : '请输入邮件中的 6 位数字验证码（如支持）。'}
                    </p>

                    <div className="space-y-4">
                      {verifyMode === 'link' ? (
                        <div className="relative">
                          <LinkIcon className="absolute left-5 top-5 text-slate-500" size={18} />
                          <textarea 
                            value={magicLink}
                            onChange={(e) => setMagicLink(e.target.value)}
                            placeholder="在此粘贴邮件中的完整链接 (包含 https://...)"
                            className="w-full bg-slate-900 border border-slate-800 rounded-2xl pl-14 pr-6 py-4 h-32 focus:outline-none focus:border-red-500 text-xs text-slate-300 break-all"
                          />
                        </div>
                      ) : (
                        <input 
                          type="text" 
                          maxLength={6}
                          value={otpCode}
                          onChange={(e) => setOtpCode(e.target.value.replace(/\D/g, ''))}
                          placeholder="000000"
                          className="w-full bg-slate-900 border border-slate-800 rounded-2xl px-6 py-4 focus:outline-none focus:border-red-500 text-center text-4xl font-black tracking-[1em] text-red-500"
                        />
                      )}

                      <button 
                        onClick={verifyMode === 'link' ? handleVerifyLink : handleVerifyOtp} 
                        className="w-full py-4 bg-white text-black hover:bg-slate-200 font-bold rounded-2xl shadow-lg transition-all active:scale-95 flex items-center justify-center space-x-2"
                      >
                        <CheckCircle size={18} />
                        <span>确认验证</span>
                      </button>
                    </div>
                  </>
                )}
              </div>
            ) : showAdmin ? (
              <AdminPanel />
            ) : (
              <>
                <h3 className="text-3xl font-bold mb-2">激活会员</h3>
                <p className="text-slate-400 text-sm mb-8">输入激活码以解锁更多高级写作诊断功能。</p>
                <div className="space-y-4">
                  <input 
                    type="text" 
                    value={activationCode}
                    onChange={(e) => setActivationCode(e.target.value)}
                    placeholder="激活码 (例如: A1B2-C3D4)"
                    className="w-full bg-slate-900 border border-slate-800 rounded-2xl px-6 py-4 focus:outline-none focus:border-red-500 uppercase font-mono tracking-widest text-white"
                  />
                  <button onClick={handleActivate} className="w-full py-4 bg-red-600 hover:bg-red-700 text-white font-bold rounded-2xl shadow-lg transition-all active:scale-95">
                    立即激活
                  </button>
                </div>
              </>
            )}

            {status.msg && (
