      headers: { 'Content-Type': 'application/json' }
    });
  } catch (err: any) {
    return new Response(JSON.stringify({ success: false, message: '生成失败: ' + err.message }), { status: 500 });
  }
}

import { User } from '../types.ts';
import { supabase } from './supabaseClient.ts';

class AuthService {
  async getCurrentUser(): Promise<User> {
    if (!supabase) return this.getMockUser();

    try {
      const { data: sessionData, error: sessionError } = await (supabase.auth as any).getSession();
      if (sessionError || !sessionData?.session?.user) {
        return this.getMockUser();
      }

      const user = sessionData.session.user;
      const { data: profile, error: profileError } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', user.id)
        .single();

      if (profileError || !profile) {
        return {
          id: user.id,
          email: user.email,
          tier: 'free',
          dailyCount: 0
        };
      }

      return {
        id: user.id,
        email: user.email,
        tier: profile.tier || 'free',
        dailyCount: profile.daily_count || 0
      };
    } catch (e) {
      console.warn("Supabase auth error, falling back to mock:", e);
      return this.getMockUser();
    }
  }

  async signIn(email: string): Promise<{ error: any }> {
    if (!supabase) return { error: new Error("数据库未连接") };
    return await (supabase.auth as any).signInWithOtp({ 
      email,
      options: {
        shouldCreateUser: true,
        emailRedirectTo: window.location.origin
      }
    });
  }

  async verifyLink(url: string): Promise<{ error: any }> {
    if (!supabase) return { error: new Error("数据库未连接") };

    try {
      let accessToken = '';
      let refreshToken = '';
      let token = '';
      let type = 'magiclink';

      // 1. 尝试解析标准的 Hash 模式 (Supabase 默认)
      if (url.includes('#')) {
        const hash = url.split('#')[1];
        const params = new URLSearchParams(hash);
        accessToken = params.get('access_token') || '';
        refreshToken = params.get('refresh_token') || '';
      }

      // 2. 尝试解析 Search 模式
      if (!accessToken) {
        const search = url.includes('?') ? url.split('?')[1] : url;
        const params = new URLSearchParams(search);
        token = params.get('token') || '';
        type = params.get('type') || 'magiclink';
      }

      if (accessToken) {
        return await (supabase.auth as any).setSession({
          access_token: accessToken,
          refresh_token: refreshToken || ''
        });
      }

      if (token) {
        return await (supabase.auth as any).verifyOtp({
          email: '', // Supabase OTP verify 对于 magiclink 往往不需要邮箱
          token,
          type: type as any
        });
      }

      throw new Error("链接格式不正确，请确保复制了完整的包含 access_token 或 token 的 URL。");
    } catch (e: any) {
      return { error: e };
    }
  }

  async verifyOtp(email: string, token: string): Promise<{ error: any }> {
    if (!supabase) return { error: new Error("数据库未连接") };
    return await (supabase.auth as any).verifyOtp({
      email,
      token,
      type: 'magiclink'
    });
  }

  async signOut() {
    if (!supabase) return;
    await (supabase.auth as any).signOut();
    window.location.reload();
  }

  async activate(code: string): Promise<{ success: boolean; message: string }> {
    if (!supabase) return { success: false, message: '数据库未连接' };
    try {
      const { data: { session } } = await (supabase.auth as any).getSession();
      if (!session) return { success: false, message: '请先登录' };
      const response = await fetch('/api/activate', {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${session.access_token}`
        },
        body: JSON.stringify({ code })
      });
      return await response.json();
    } catch (error) {
      return { success: false, message: '激活码验证失败' };
    }
  }

  getMockUser(): User {
    return { id: 'GUEST-USER', tier: 'free', dailyCount: 0 };
  }
}

