        dailyCount: profile.daily_count || 0
      };
    } catch (e) {
      console.warn("Supabase auth error, falling back to mock:", e);
      return this.getMockUser();
    }
  }

  async signIn(email: string): Promise<{ error: any }> {
    if (!supabase) return { error: new Error("数据库未连接") };
    return await (supabase.auth as any).signInWithOtp({ 
      email,
      options: {
        shouldCreateUser: true,
        emailRedirectTo: window.location.origin
      }
    });
  }

  /**
   * 增强型链接解析：支持从包含 localhost 的错误链接中恢复 access_token
   */
  async verifyLink(url: string): Promise<{ error: any }> {
    if (!supabase) return { error: new Error("数据库未连接") };

    try {
      // 预处理：去掉可能存在的引号或多余空格
      const cleanUrl = url.trim().replace(/^["']|["']$/g, '');

      let accessToken = '';
      let refreshToken = '';

      // 情况 A：标准的 Supabase Hash 模式 (包含 #access_token=...)
      if (cleanUrl.includes('#')) {
        const hashPart = cleanUrl.split('#')[1];
        const params = new URLSearchParams(hashPart);
        accessToken = params.get('access_token') || '';
        refreshToken = params.get('refresh_token') || '';
      }

      // 情况 B：Query Parameter 模式 (包含 ?access_token=...)
      if (!accessToken && cleanUrl.includes('?')) {
        const queryPart = cleanUrl.split('?')[1];
        const params = new URLSearchParams(queryPart);
        accessToken = params.get('access_token') || '';
        refreshToken = params.get('refresh_token') || '';
      }

      // 情况 C：Magic Link Token 模式 (验证码式链接)
      if (!accessToken) {
        const params = new URLSearchParams(cleanUrl.includes('?') ? cleanUrl.split('?')[1] : cleanUrl);
        const token = params.get('token') || '';
        const type = params.get('type') || 'magiclink';

        if (token) {
          return await (supabase.auth as any).verifyOtp({
            email: '', 
            token,
            type: type as any
          });
        }
      }

      if (accessToken) {
        console.log("正在尝试使用提取的 Access Token 建立会话...");
        return await (supabase.auth as any).setSession({
          access_token: accessToken,
          refresh_token: refreshToken || ''
        });
      }

      throw new Error("链接无效或格式不完整。请确保复制了完整的包含 'access_token=' 的地址。");
    } catch (e: any) {
      return { error: e };
    }
  }

  async verifyOtp(email: string, token: string): Promise<{ error: any }> {
    if (!supabase) return { error: new Error("数据库未连接") };
    return await (supabase.auth as any).verifyOtp({
      email,
      token,
      type: 'magiclink'
    });
  }

  async signOut() {
    if (!supabase) return;
    await (supabase.auth as any).signOut();
    window.location.reload();
  }

  async activate(code: string): Promise<{ success: boolean; message: string }> {
    if (!supabase) return { success: false, message: '数据库未连接' };
    try {
      const { data: { session } } = await (supabase.auth as any).getSession();
      if (!session) return { success: false, message: '请先登录' };
      const response = await fetch('/api/activate', {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${session.access_token}`
        },
        body: JSON.stringify({ code })
      });
      return await response.json();
    } catch (error) {
      return { success: false, message: '激活码验证失败' };
    }
  }

  getMockUser(): User {
    return { id: 'GUEST-USER', tier: 'free', dailyCount: 0 };
  }
}

