import crypto from 'node:crypto';
// @ts-ignore
import { createClient } from '@supabase/supabase-js';

export default async function handler(req: any, res: any) {
  if (req.method !== 'POST') return res.status(405).json({ message: 'Method not allowed' });

  const { newUsername, newPassword } = req.body;
  const authHeader = req.headers.authorization;

  const supabaseUrl = process.env.SUPABASE_URL;
  const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY;

  if (!authHeader || !supabaseUrl || !serviceKey) {
    return res.status(401).json({ message: '配置缺失' });
  }

  try {
    const supabaseAdmin = createClient(supabaseUrl, serviceKey);
    const token = authHeader.split(' ')[1];

    // 1. 严格验证当前会话是否属于白名单管理员
    const { data: { user }, error: authError } = await (supabaseAdmin.auth as any).getUser(token);
    const ADMIN_EMAILS = ['admin@example.com', 'soralabe@foxmail.com', 'yutongli895@gmail.com'];

    if (authError || !user || !ADMIN_EMAILS.includes(user.email || '')) {
      return res.status(403).json({ message: '只有白名单邮箱用户有权重置凭据' });
    }

    // 2. 生成新的加密数据
    const salt = crypto.randomBytes(16).toString('hex');
    const hash = crypto.scryptSync(newPassword, salt, 64).toString('hex');

    // 3. 先清空旧数据，再插入新数据（确保唯一性）
    await supabaseAdmin.from('admin_credentials').delete().neq('id', '00000000-0000-0000-0000-000000000000'); // 删除所有

    const { error: insertError } = await supabaseAdmin.from('admin_credentials').insert({
      username: newUsername,
      password_hash: hash,
      salt: salt
    });

    if (insertError) throw insertError;

    return res.status(200).json({ success: true, message: '凭据重置成功！请重新登录。' });
  } catch (err: any) {
    return res.status(500).json({ success: false, message: '重置失败: ' + err.message });
  }
}

import { createClient } from '@supabase/supabase-js';
import crypto from 'node:crypto';

export async function onRequest(context: any) {
  const { request, env } = context;
  if (request.method !== 'POST') return new Response('Method not allowed', { status: 405 });

  const { newUsername, newPassword } = await request.json();
  const authHeader = request.headers.get('authorization');

  const supabaseUrl = env.SUPABASE_URL;
  const serviceKey = env.SUPABASE_SERVICE_ROLE_KEY;

  if (!authHeader || !supabaseUrl || !serviceKey) {
    return new Response(JSON.stringify({ message: '配置缺失' }), { status: 401 });
  }

  try {
    const supabaseAdmin = createClient(supabaseUrl, serviceKey);
    const token = authHeader.split(' ')[1];

    const { data: { user } } = await (supabaseAdmin.auth as any).getUser(token);
    const ADMIN_EMAILS = ['admin@example.com', 'soralabe@foxmail.com', 'yutongli895@gmail.com'];

    if (!user || !ADMIN_EMAILS.includes(user.email || '')) {
      return new Response(JSON.stringify({ message: '拒绝访问' }), { status: 403 });
    }

    const salt = crypto.randomBytes(16).toString('hex');
    const hash = crypto.scryptSync(newPassword, salt, 64).toString('hex');

    await supabaseAdmin.from('admin_credentials').delete().neq('id', '00000000-0000-0000-0000-000000000000');

    const { error: insertError } = await supabaseAdmin.from('admin_credentials').insert({
      username: newUsername,
      password_hash: hash,
      salt: salt
    });

    if (insertError) throw insertError;

    return new Response(JSON.stringify({ success: true, message: '凭据重置成功' }), {
      headers: { 'Content-Type': 'application/json' }
    });
  } catch (err: any) {
    return new Response(JSON.stringify({ success: false, message: '错误: ' + err.message }), { status: 500 });
  }
}

