      const response = await fetch('/api/admin/auth', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${session?.access_token}`
        },
        body: JSON.stringify({ username, password })
      });

      const result = await response.json();
      if (result.success) {
        setIsAuthorized(true);
        sessionStorage.setItem('admin_verified', 'true');
      } else {
        setAuthError(result.message || '登录失败');
      }
    } catch (err) {
      setAuthError('连接服务器失败');
    } finally {
      setAuthLoading(false);
    }
  };

  const handleResetCredentials = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!resetData.user || !resetData.pass) return;
    setResetLoading(true);
    try {
      const { data: { session } } = await (supabase!.auth as any).getSession();
      const response = await fetch('/api/admin/reset', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${session?.access_token}`
        },
        body: JSON.stringify({ 
          newUsername: resetData.user, 
          newPassword: resetData.pass 
        })
      });
      const result = await response.json();
      if (result.success) {
        alert("管理员账号密码已更新，请使用新凭据登录。");
        setShowReset(false);
        setAuthError('');
      } else {
        alert(result.message);
      }
    } catch (err) {
      alert("请求失败");
    } finally {
      setResetLoading(false);
    }
  };

  const generateCodes = async () => {
    setIsGenerating(true);
    try {
      const { data: { session } } = await (supabase!.auth as any).getSession();
      const response = await fetch('/api/admin/generate', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${session?.access_token}`
        },
        body: JSON.stringify({ tier, count })
      });
      const result = await response.json();
      if (result.success) {
        setNewCodes(result.codes);
      } else {
        alert(result.message);
      }
    } catch (err) {
      alert("生成失败");
    } finally {
      setIsGenerating(false);
    }
  };

  const copyToClipboard = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopiedIndex(index);
    setTimeout(() => setCopiedIndex(null), 2000);
  };

  if (!isAuthorized) {
    return (
      <div className="space-y-8 animate-in fade-in duration-500">
        <div className="text-center">
          <div className="inline-flex p-4 rounded-3xl bg-red-600/10 mb-4 border border-red-500/20">
            <ShieldAlert className="text-red-500 w-10 h-10" />
          </div>
          <h2 className="text-2xl font-bold text-white">
            {showReset ? '重置管理员凭据' : '管理员二次验证'}
          </h2>
          <p className="text-slate-500 text-xs mt-2 uppercase tracking-widest font-bold">
            {showReset ? 'Reset Your Credentials' : 'Secure Access Required'}
          </p>
        </div>

        {!showReset ? (
          <form onSubmit={handleAdminLogin} className="space-y-4">
            <div className="relative">
              <UserIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
              <input 
                type="text"
                required
                placeholder="管理员用户名"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                className="w-full bg-slate-900 border border-slate-800 rounded-2xl pl-12 pr-6 py-4 text-sm focus:outline-none focus:border-red-500 text-white transition-all"
              />
            </div>
            <div className="relative">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
              <input 
                type="password"
                required
                placeholder="安全密码"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full bg-slate-900 border border-slate-800 rounded-2xl pl-12 pr-6 py-4 text-sm focus:outline-none focus:border-red-500 text-white transition-all"
              />
            </div>

            {authError && (
              <div className="space-y-3">
                <div className="p-3 bg-red-500/10 border border-red-500/20 rounded-xl text-red-400 text-xs text-center font-bold">
                  {authError}
                </div>
                <button 
                  type="button"
                  onClick={() => setShowReset(true)}
                  className="w-full text-[10px] text-slate-500 hover:text-red-400 transition-colors font-bold uppercase tracking-widest flex items-center justify-center space-x-1"
                >
                  <RefreshCw size={10} />
                  <span>如果您忘记了凭据，点击此处重置</span>
                </button>
              </div>
            )}

            <button 
              type="submit"
              disabled={authLoading}
              className="w-full py-4 bg-red-600 hover:bg-red-700 text-white font-bold rounded-2xl shadow-xl shadow-red-600/20 transition-all flex items-center justify-center space-x-2 active:scale-95 disabled:opacity-50"
            >
              {authLoading ? <Loader2 className="animate-spin" size={20} /> : <ShieldCheck size={20} />}
              <span>解锁管理权限</span>
            </button>
          </form>
        ) : (
          <form onSubmit={handleResetCredentials} className="space-y-4">
            <div className="bg-amber-500/10 border border-amber-500/20 p-4 rounded-xl mb-4">
              <p className="text-[10px] text-amber-200 leading-relaxed">
                <strong>安全提示：</strong>只有当您当前的会话属于白名单邮箱（yutongli895@gmail.com）时，此重置才会生效。新凭据将直接写入数据库。
              </p>
            </div>
            <div className="relative">
              <Key className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
              <input 
                type="text"
                required
                placeholder="设置新用户名"
                value={resetData.user}
                onChange={(e) => setResetData({...resetData, user: e.target.value})}
                className="w-full bg-slate-900 border border-slate-800 rounded-2xl pl-12 pr-6 py-4 text-sm focus:outline-none focus:border-red-500 text-white transition-all"
              />
            </div>
            <div className="relative">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
              <input 
                type="password"
                required
                placeholder="设置新密码"
                value={resetData.pass}
                onChange={(e) => setResetData({...resetData, pass: e.target.value})}
                className="w-full bg-slate-900 border border-slate-800 rounded-2xl pl-12 pr-6 py-4 text-sm focus:outline-none focus:border-red-500 text-white transition-all"
              />
            </div>

            <div className="flex space-x-3 pt-4">
              <button 
                type="button"
                onClick={() => setShowReset(false)}
                className="flex-1 py-4 bg-slate-900 text-slate-400 font-bold rounded-2xl border border-slate-800 hover:border-slate-700 transition-all"
              >
                取消
              </button>
              <button 
                type="submit"
                disabled={resetLoading}
                className="flex-[2] py-4 bg-white text-black font-bold rounded-2xl shadow-xl transition-all flex items-center justify-center space-x-2 active:scale-95"
              >
                {resetLoading ? <Loader2 className="animate-spin" size={20} /> : <RefreshCw size={20} />}
                <span>确认重置并应用</span>
              </button>
            </div>
          </form>
        )}
      </div>
    );
  }

  // 验证通过后的管理功能界面
  return (
    <div className="space-y-6 animate-in zoom-in-95 duration-300">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center space-x-3">
          <ShieldCheck className="text-green-500" />
          <h2 className="text-xl font-bold text-white">激活码发放中心</h2>
        </div>
        <div className="px-3 py-1 bg-green-500/10 text-green-400 text-[10px] font-bold rounded-full border border-green-500/20">
          已授权访问
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div className="space-y-2">
          <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">会员等级</label>
          <div className="flex bg-slate-900 rounded-xl p-1 border border-slate-800">
            <button 
              onClick={() => setTier('pro')}
              className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${tier === 'pro' ? 'bg-red-600 text-white' : 'text-slate-400 hover:text-white'}`}
            >精进版 (PRO)</button>
            <button 
              onClick={() => setTier('plus')}
              className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${tier === 'plus' ? 'bg-red-600 text-white' : 'text-slate-400 hover:text-white'}`}
            >全能版 (PLUS)</button>
          </div>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">生成数量</label>
          <input 
            type="number" 
            min="1" max="50"
            value={count}
            onChange={(e) => setCount(parseInt(e.target.value))}
            className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-2.5 text-sm text-white focus:outline-none focus:border-red-500"
          />
        </div>
      </div>

      <button 
        onClick={generateCodes}
        disabled={isGenerating}
        className="w-full py-4 bg-white text-black font-bold rounded-2xl hover:bg-slate-200 transition-all flex items-center justify-center space-x-2 shadow-xl shadow-white/5 disabled:opacity-50 active:scale-95"
      >
        {isGenerating ? <Loader2 className="animate-spin" size={18} /> : <Zap size={18} />}
        <span>批量创建激活码</span>
      </button>

      {newCodes.length > 0 && (
        <div className="mt-8 space-y-3 max-h-60 overflow-y-auto pr-2 scroll-custom">
          {newCodes.map((item, idx) => (
            <div key={idx} className="flex items-center justify-between p-4 bg-slate-900/50 border border-slate-800 rounded-2xl group hover:border-red-500/30 transition-all">
              <div>
                <span className="text-xs font-mono font-bold text-red-400 mr-3 tracking-widest uppercase">{item.code}</span>
                <span className="text-[10px] bg-slate-800 text-slate-400 px-2 py-0.5 rounded uppercase font-bold">{item.tier}</span>
              </div>
              <button 
                onClick={() => copyToClipboard(item.code, idx)}
                className="text-slate-500 hover:text-white transition-colors"
              >
                {copiedIndex === idx ? <Check size={16} className="text-green-500" /> : <Copy size={16} />}
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

{
