      // 允许访问根目录以外的文件（如果需要）
      allow: ['..']
    }
  }
});

import React, { useState, useEffect } from 'react';
import { ShieldCheck, Copy, Check, Loader2, Zap, Lock, User as UserIcon, ShieldAlert, RefreshCw, Key, Info } from 'lucide-react';
import { supabase } from '../services/supabaseClient';

const AdminPanel: React.FC = () => {
  const [isAuthorized, setIsAuthorized] = useState(false);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [authLoading, setAuthLoading] = useState(false);
  const [authError, setAuthError] = useState('');

  const [showReset, setShowReset] = useState(false);
  const [resetData, setResetData] = useState({ user: '', pass: '' });
  const [resetLoading, setResetLoading] = useState(false);

  const [tier, setTier] = useState<'pro' | 'plus'>('pro');
  const [count, setCount] = useState(1);
  const [isGenerating, setIsGenerating] = useState(false);
  const [newCodes, setNewCodes] = useState<any[]>([]);
  const [copiedIndex, setCopiedIndex] = useState<number | null>(null);

  // 检查是否已经验证过（Session 级别）
  useEffect(() => {
    if (sessionStorage.getItem('admin_verified') === 'true') {
      setIsAuthorized(true);
    }
  }, []);

  const handleAdminLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setAuthLoading(true);
    setAuthError('');

    try {
      const { data: { session } } = await (supabase!.auth as any).getSession();
      const response = await fetch('/api/admin/auth', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${session?.access_token}`
        },
        body: JSON.stringify({ username, password })
      });

      const result = await response.json();
      if (result.success) {
        setIsAuthorized(true);
        sessionStorage.setItem('admin_verified', 'true');
      } else {
        setAuthError(result.message || '密码错误或用户不存在');
      }
    } catch (err) {
      setAuthError('连接认证服务器失败，请检查网络');
    } finally {
      setAuthLoading(false);
    }
  };

  const handleResetCredentials = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!resetData.user || !resetData.pass) return;
    if (resetData.pass.length < 8) {
      alert("为了安全，新密码长度不能少于 8 位");
      return;
    }

    setResetLoading(true);
    try {
      const { data: { session } } = await (supabase!.auth as any).getSession();
      const response = await fetch('/api/admin/reset', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${session?.access_token}`
        },
        body: JSON.stringify({ 
          newUsername: resetData.user, 
          newPassword: resetData.pass 
        })
      });
      const result = await response.json();
      if (result.success) {
        alert("重置成功！请使用新凭据登录。");
        setShowReset(false);
        setAuthError('');
        setUsername(resetData.user);
      } else {
        alert("重置失败：" + result.message);
      }
    } catch (err) {
      alert("请求发送失败，请重试。");
    } finally {
      setResetLoading(false);
    }
  };

  const generateCodes = async () => {
    setIsGenerating(true);
    try {
      const { data: { session } } = await (supabase!.auth as any).getSession();
      const response = await fetch('/api/admin/generate', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${session?.access_token}`
        },
        body: JSON.stringify({ tier, count })
      });
      const result = await response.json();
      if (result.success) {
        setNewCodes(result.codes);
      } else {
        alert(result.message);
      }
    } catch (err) {
      alert("生成失败");
    } finally {
      setIsGenerating(false);
    }
  };

  const copyToClipboard = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopiedIndex(index);
    setTimeout(() => setCopiedIndex(null), 2000);
  };

  if (!isAuthorized) {
    return (
      <div className="space-y-8 animate-in fade-in duration-500">
