          <div className="inline-flex p-4 rounded-3xl bg-red-600/10 mb-4 border border-red-500/20">
            <ShieldAlert className={`${showReset ? 'text-amber-500' : 'text-red-500'} w-10 h-10`} />
          </div>
          <h2 className="text-2xl font-bold text-white">
            {showReset ? '重置管理员凭据' : '管理员二次验证'}
          </h2>
          <p className="text-slate-500 text-[10px] mt-2 uppercase tracking-widest font-bold">
            {showReset ? 'Emergency Credential Reset' : 'Secure Access Required'}
          </p>
        </div>

        {!showReset ? (
          <form onSubmit={handleAdminLogin} className="space-y-4">
            <div className="relative">
              <UserIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
              <input 
                type="text"
                required
                placeholder="管理员用户名"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                className="w-full bg-slate-900 border border-slate-800 rounded-2xl pl-12 pr-6 py-4 text-sm focus:outline-none focus:border-red-500 text-white transition-all"
              />
            </div>
            <div className="relative">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
              <input 
                type="password"
                required
                placeholder="安全密码"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full bg-slate-900 border border-slate-800 rounded-2xl pl-12 pr-6 py-4 text-sm focus:outline-none focus:border-red-500 text-white transition-all"
              />
            </div>

            {authError && (
              <div className="space-y-4 animate-in slide-in-from-top-2">
                <div className="p-4 bg-red-500/10 border border-red-500/20 rounded-2xl text-red-400 text-xs text-center font-bold">
                  {authError}
                </div>
                <div className="bg-slate-900/50 border border-slate-800 p-4 rounded-2xl">
                  <p className="text-[10px] text-slate-500 mb-3 text-center leading-relaxed">
                    初次使用或忘记密码？您可以通过已登录的白名单邮箱强制重置凭据。
                  </p>
                  <button 
                    type="button"
                    onClick={() => setShowReset(true)}
                    className="w-full py-2.5 bg-red-600/10 hover:bg-red-600/20 border border-red-500/30 text-[10px] text-red-400 font-bold uppercase tracking-widest rounded-xl transition-all flex items-center justify-center space-x-2"
                  >
                    <RefreshCw size={12} />
                    <span>立即重置账号密码</span>
                  </button>
                </div>
              </div>
            )}

            {!authError && (
              <button 
                type="submit"
                disabled={authLoading}
                className="w-full py-4 bg-red-600 hover:bg-red-700 text-white font-bold rounded-2xl shadow-xl shadow-red-600/20 transition-all flex items-center justify-center space-x-2 active:scale-95 disabled:opacity-50"
              >
                {authLoading ? <Loader2 className="animate-spin" size={20} /> : <ShieldCheck size={20} />}
                <span>解锁管理权限</span>
              </button>
            )}
          </form>
        ) : (
          <form onSubmit={handleResetCredentials} className="space-y-4">
            <div className="bg-amber-500/10 border border-amber-500/20 p-5 rounded-2xl mb-4">
              <div className="flex items-start space-x-3">
                <Info className="text-amber-500 shrink-0 mt-0.5" size={16} />
                <p className="text-[10px] text-amber-200/80 leading-relaxed">
                  <strong>重置规则：</strong>此操作将清除现有管理员账号。系统会验证您当前的 <strong>Supabase Session</strong> 是否属于白名单邮箱。验证通过后即可应用新凭据。
                </p>
              </div>
            </div>
            <div className="relative">
              <UserIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
              <input 
                type="text"
                required
                placeholder="设置新用户名"
                value={resetData.user}
                onChange={(e) => setResetData({...resetData, user: e.target.value})}
                className="w-full bg-slate-900 border border-slate-800 rounded-2xl pl-12 pr-6 py-4 text-sm focus:outline-none focus:border-red-500 text-white transition-all"
              />
            </div>
            <div className="relative">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
              <input 
                type="password"
                required
                placeholder="设置新密码 (至少8位)"
                value={resetData.pass}
                onChange={(e) => setResetData({...resetData, pass: e.target.value})}
                className="w-full bg-slate-900 border border-slate-800 rounded-2xl pl-12 pr-6 py-4 text-sm focus:outline-none focus:border-red-500 text-white transition-all"
              />
            </div>

            <div className="flex space-x-3 pt-4">
              <button 
                type="button"
                onClick={() => setShowReset(false)}
                className="flex-1 py-4 bg-slate-900 text-slate-400 font-bold rounded-2xl border border-slate-800 hover:border-slate-700 transition-all text-xs"
              >
                返回
              </button>
              <button 
                type="submit"
                disabled={resetLoading}
                className="flex-[2] py-4 bg-white text-black font-bold rounded-2xl shadow-xl transition-all flex items-center justify-center space-x-2 active:scale-95 text-xs"
              >
                {resetLoading ? <Loader2 className="animate-spin" size={18} /> : <RefreshCw size={18} />}
                <span>确认重置并应用</span>
              </button>
            </div>
          </form>
        )}
      </div>
    );
  }

