  return (
    <div className="space-y-6 animate-in zoom-in-95 duration-300">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center space-x-3">
          <ShieldCheck className="text-green-500" />
          <h2 className="text-xl font-bold text-white">激活码发放中心</h2>
        </div>
        <div className="px-3 py-1 bg-green-500/10 text-green-400 text-[10px] font-bold rounded-full border border-green-500/20">
          已授权访问
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div className="space-y-2">
          <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">会员等级</label>
          <div className="flex bg-slate-900 rounded-xl p-1 border border-slate-800">
            <button 
              onClick={() => setTier('pro')}
              className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${tier === 'pro' ? 'bg-red-600 text-white' : 'text-slate-400 hover:text-white'}`}
