          />
        </div>
      </div>

      <button 
        onClick={generateCodes}
        disabled={isGenerating}
        className="w-full py-4 bg-white text-black font-bold rounded-2xl hover:bg-slate-200 transition-all flex items-center justify-center space-x-2 shadow-xl shadow-white/5 disabled:opacity-50 active:scale-95"
      >
        {isGenerating ? <Loader2 className="animate-spin" size={18} /> : <Zap size={18} />}
        <span>批量创建激活码</span>
      </button>

      {newCodes.length > 0 && (
        <div className="mt-8 space-y-3 max-h-60 overflow-y-auto pr-2 scroll-custom">
          {newCodes.map((item, idx) => (
            <div key={idx} className="flex items-center justify-between p-4 bg-slate-900/50 border border-slate-800 rounded-2xl group hover:border-red-500/30 transition-all">
              <div>
                <span className="text-xs font-mono font-bold text-red-400 mr-3 tracking-widest uppercase">{item.code}</span>
                <span className="text-[10px] bg-slate-800 text-slate-400 px-2 py-0.5 rounded uppercase font-bold">{item.tier}</span>
              </div>
              <button 
                onClick={() => copyToClipboard(item.code, idx)}
                className="text-slate-500 hover:text-white transition-colors"
              >
                {copiedIndex === idx ? <Check size={16} className="text-green-500" /> : <Copy size={16} />}
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

