import { createClient } from '@supabase/supabase-js';
import crypto from 'node:crypto';

export async function onRequest(context: any) {
  const { request, env } = context;
  if (request.method !== 'POST') return new Response('Method not allowed', { status: 405 });

  const { newUsername, newPassword } = await request.json();
  const authHeader = request.headers.get('authorization');

  const supabaseUrl = env.SUPABASE_URL;
  const serviceKey = env.SUPABASE_SERVICE_ROLE_KEY;

  if (!authHeader || !supabaseUrl || !serviceKey) {
    return new Response(JSON.stringify({ message: '配置缺失' }), { status: 401 });
  }

  try {
    const supabaseAdmin = createClient(supabaseUrl, serviceKey);
    const token = authHeader.split(' ')[1];

    const { data: { user }, error: authError } = await (supabaseAdmin.auth as any).getUser(token);
    const ADMIN_EMAILS = ['admin@example.com', 'soralabe@foxmail.com', 'yutongli895@gmail.com'];

    if (authError || !user || !ADMIN_EMAILS.includes(user.email || '')) {
      return new Response(JSON.stringify({ message: '您当前的邮箱无权执行此敏感操作' }), { status: 403 });
    }

    // 生成盐和 Hash
    const salt = crypto.randomBytes(16).toString('hex');
    const hash = crypto.scryptSync(newPassword, salt, 64).toString('hex');

    // 清除旧数据：使用更通用的过滤条件
    await supabaseAdmin.from('admin_credentials').delete().neq('username', '_system_reserved_');

    // 插入新凭据
    const { error: insertError } = await supabaseAdmin.from('admin_credentials').insert({
      username: newUsername,
      password_hash: hash,
      salt: salt
    });

    if (insertError) throw insertError;

    return new Response(JSON.stringify({ success: true, message: '凭据重置成功' }), {
      headers: { 'Content-Type': 'application/json' }
    });
  } catch (err: any) {
    return new Response(JSON.stringify({ success: false, message: '后端重置逻辑出错: ' + err.message }), { status: 500 });
  }
}

import { createClient } from '@supabase/supabase-js';
import crypto from 'node:crypto';

export async function onRequest(context: any) {
  const { request, env } = context;
  if (request.method !== 'POST') return new Response('Method not allowed', { status: 405 });

  const { username, password } = await request.json();
  const authHeader = request.headers.get('authorization');

  const supabaseUrl = env.SUPABASE_URL;
  const serviceKey = env.SUPABASE_SERVICE_ROLE_KEY;

  if (!authHeader || !supabaseUrl || !serviceKey) {
    return new Response(JSON.stringify({ message: '服务端环境变量配置不完整' }), { status: 401 });
  }

  try {
    const supabaseAdmin = createClient(supabaseUrl, serviceKey);
    const token = authHeader.split(' ')[1];

    // 1. 验证白名单
    const { data: { user } } = await (supabaseAdmin.auth as any).getUser(token);
    const ADMIN_EMAILS = ['admin@example.com', 'soralabe@foxmail.com', 'yutongli895@gmail.com'];
    if (!user || !ADMIN_EMAILS.includes(user.email || '')) {
      return new Response(JSON.stringify({ message: '当前 Gmail 邮箱无权访问后台' }), { status: 403 });
    }

    // 2. 查询凭据
    const { data: adminData, error: dbError } = await supabaseAdmin
      .from('admin_credentials')
      .select('*')
      .eq('username', username)
      .single();

    if (dbError || !adminData) {
      return new Response(JSON.stringify({ success: false, message: '管理员用户名不存在，请重置' }), { status: 401 });
    }

    // 3. 验证 Hash
    const derivedKey = crypto.scryptSync(password, adminData.salt, 64);
    const isValid = derivedKey.toString('hex') === adminData.password_hash;

    if (isValid) {
      return new Response(JSON.stringify({ 
        success: true, 
        message: '二次验证通过'
      }), { headers: { 'Content-Type': 'application/json' } });
    } else {
      return new Response(JSON.stringify({ success: false, message: '安全密码错误，请检查或点击重置' }), { status: 401 });
    }
  } catch (err: any) {
    return new Response(JSON.stringify({ success: false, message: '认证服务器异常: ' + err.message }), { status: 500 });
  }
}

import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar.tsx';
import Hero from './components/Hero.tsx';
import Features from './components/Features.tsx';
import CompositionWorkspace from './components/CompositionWorkspace.tsx';
import AIChatPreview from './components/AIChatPreview.tsx';
import Pricing from './components/Pricing.tsx';
import Footer from './components/Footer.tsx';
import AdminPanel from './components/AdminPanel.tsx';
import { authService } from './services/authService.ts';
import { User } from './types.ts';
import { KeyRound, X, CheckCircle, Loader2, AlertTriangle, ShieldCheck, LogIn, LogOut, ArrowLeft, Mail, Link as LinkIcon, Info, ExternalLink } from 'lucide-react';
import { supabase } from './services/supabaseClient.ts';

const App: React.FC = () => {
  const [user, setUser] = useState<User>(authService.getMockUser());
  const [loading, setLoading] = useState(true);
  const [showActivation, setShowActivation] = useState(false);
  const [showAdmin, setShowAdmin] = useState(false);
  const [showLogin, setShowLogin] = useState(false);

  const [loginStep, setLoginStep] = useState<'email' | 'verify'>('email');
  const [email, setEmail] = useState('');
  const [magicLink, setMagicLink] = useState('');

  const [activationCode, setActivationCode] = useState('');
  const [status, setStatus] = useState<{ type: 'success' | 'error' | null, msg: string }>({ type: null, msg: '' });

  const ADMIN_EMAILS = ['admin@example.com', 'soralabe@foxmail.com', 'yutongli895@gmail.com'];
  const isAdmin = user.email && ADMIN_EMAILS.includes(user.email);

  useEffect(() => {
    const checkUrlForAuth = async () => {
      const url = window.location.href;
      if (url.includes('access_token=') || url.includes('token=')) {
        setStatus({ type: null, msg: '侦测到登录凭证，正在自动建立会话...' });
        const { error } = await authService.verifyLink(url);
        if (!error) {
          handleLoginSuccess();
          window.history.replaceState(null, '', window.location.pathname);
        } else {
          setStatus({ type: 'error', msg: '自动登录失败：' + error.message });
          setShowLogin(true);
          setLoginStep('verify');
        }
      }
    };

    const initAuth = async () => {
      try {
        const currentUser = await authService.getCurrentUser();
        if (currentUser) setUser(currentUser);
        await checkUrlForAuth();
      } finally {
        setLoading(false);
      }
    };
    initAuth();

    if (supabase) {
      const { data } = (supabase.auth as any).onAuthStateChange(async (event: string) => {
        const updatedUser = await authService.getCurrentUser();
        setUser(updatedUser);
        if (event === 'SIGNED_IN' && isAdmin) {
           setShowLogin(false);
           setShowActivation(true);
           setShowAdmin(true);
        }
      });
      return () => data.subscription.unsubscribe();
    }
  }, [isAdmin]);

  const handleSendOtp = async () => {
    if (!email) return;
    setStatus({ type: null, msg: '正在请求登录凭证...' });
    const { error } = await authService.signIn(email);
    if (error) {
      setStatus({ type: 'error', msg: error.message });
    } else {
      setLoginStep('verify');
      setStatus({ type: 'success', msg: '验证邮件已发送！' });
    }
  };

  const handleVerifyLink = async () => {
    if (!magicLink) return;
    setStatus({ type: null, msg: '正在解析链接并建立安全会话...' });
    const { error } = await authService.verifyLink(magicLink);
    if (error) {
      setStatus({ type: 'error', msg: '验证失败：' + error.message });
    } else {
      handleLoginSuccess();
    }
  };

  const handleLoginSuccess = async () => {
    const updatedUser = await authService.getCurrentUser();
    setUser(updatedUser);
    setStatus({ type: 'success', msg: '身份验证成功！' });
    setTimeout(() => {
        setShowLogin(false);
        if (ADMIN_EMAILS.includes(updatedUser.email || '')) {
            setShowActivation(true);
            setShowAdmin(true);
        }
    }, 1000);
  };

  const handleActivate = async () => {
    if (!activationCode) return;
    setStatus({ type: null, msg: '正在验证...' });
    const result = await authService.activate(activationCode);
    if (result.success) {
      const updatedUser = await authService.getCurrentUser();
      setUser(updatedUser);
      setStatus({ type: 'success', msg: result.message });
      setTimeout(() => setShowActivation(false), 2000);
    } else {
      setStatus({ type: 'error', msg: result.message });
    }
  };

  if (loading) return (
    <div className="min-h-screen bg-slate-950 flex items-center justify-center">
      <Loader2 className="animate-spin text-red-500" size={40} />
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 selection:bg-red-500 selection:text-white">
      <Navbar />
      <main>
        <div className="pt-28 px-6 max-w-7xl mx-auto flex flex-wrap gap-3 justify-end items-center">
          {isAdmin && (
            <button 
              onClick={() => { setShowActivation(true); setShowAdmin(true); setStatus({type:null, msg:''}); }}
              className="flex items-center space-x-2 text-xs font-bold py-2.5 px-5 bg-red-600/10 border border-red-500/30 rounded-full hover:bg-red-600/20 transition-all text-red-400"
            >
              <ShieldCheck size={14} />
              <span>管理后台</span>
            </button>
          )}

          <div className="flex items-center bg-slate-900 border border-slate-800 rounded-full px-4 py-1.5 space-x-3 shadow-lg shadow-black/20">
             <div className="flex flex-col text-right">
                <span className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                  {user.email || '游客模式'}
