                          className="w-full bg-slate-900 border border-slate-800 rounded-2xl pl-14 pr-6 py-4 h-24 focus:outline-none focus:border-red-500 text-[10px] font-mono text-slate-400 break-all leading-relaxed"
                        />
                      </div>

                      <button 
                        onClick={handleVerifyLink} 
                        className="w-full py-4 bg-white text-black hover:bg-slate-200 font-bold rounded-2xl shadow-lg transition-all active:scale-95 flex items-center justify-center space-x-2"
                      >
                        <CheckCircle size={18} />
                        <span>确认解析并登录</span>
                      </button>
                    </div>
                  </>
                )}
              </div>
            ) : showAdmin ? (
              <AdminPanel />
            ) : (
              <>
                <h3 className="text-3xl font-bold mb-2">激活会员</h3>
                <p className="text-slate-400 text-sm mb-8">输入激活码以解锁更多高级写作诊断功能。</p>
                <div className="space-y-4">
                  <input 
                    type="text" 
                    value={activationCode}
                    onChange={(e) => setActivationCode(e.target.value)}
                    placeholder="激活码 (例如: A1B2-C3D4)"
                    className="w-full bg-slate-900 border border-slate-800 rounded-2xl px-6 py-4 focus:outline-none focus:border-red-500 uppercase font-mono tracking-widest text-white"
                  />
                  <button onClick={handleActivate} className="w-full py-4 bg-red-600 hover:bg-red-700 text-white font-bold rounded-2xl shadow-lg transition-all active:scale-95">
                    立即激活
                  </button>
                </div>
              </>
            )}

            {status.msg && (
              <div className={`mt-6 p-4 rounded-2xl text-xs flex items-center space-x-3 animate-in fade-in zoom-in duration-300 ${status.type === 'success' ? 'bg-green-600/10 text-green-400 border border-green-500/20' : 'bg-red-600/10 text-red-400 border border-red-500/20'}`}>
                {status.type === 'success' ? <CheckCircle size={16} /> : <AlertTriangle size={16} />}
                <span className="font-medium leading-relaxed">{status.msg}</span>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

