                        <button 
                          onClick={() => handleCopy(msg.content)}
                          className="absolute top-2 right-2 p-1.5 bg-black/40 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity"
                        >
                          {copied ? <Check className="w-3 h-3 text-emerald-400" /> : <Copy className="w-3 h-3" />}
                        </button>
                      )}
                    </div>
                  </div>
                </MotionDiv>
              ))}
              {isLoading && (
                <MotionDiv initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex gap-4">
                  <div className="w-8 h-8 rounded-full bg-white/10 flex items-center justify-center shrink-0">
                    <Bot className="w-4 h-4" />
                  </div>
                  <div className="p-4 md:p-5 rounded-2xl bg-white/5 border border-white/10 flex items-center gap-3">
                    <Loader2 className="w-3 h-3 md:w-4 md:h-4 animate-spin text-emerald-400" />
                    <span className="text-[10px] md:text-xs text-white/40 tracking-widest">语枢正在智能构建教学资源...</span>
                  </div>
                </MotionDiv>
              )}
            </AnimatePresence>
          </div>

          <div className="p-4 md:p-6 border-t border-white/5 bg-white/[0.03]">
            {/* 图片预览区域 */}
            <AnimatePresence>
              {selectedImage && (
                <MotionDiv 
                  initial={{ opacity: 0, height: 0, marginBottom: 0 }} 
                  animate={{ opacity: 1, height: 'auto', marginBottom: 12 }} 
                  exit={{ opacity: 0, height: 0, marginBottom: 0 }}
                  className="relative inline-block"
                >
                  <div className="relative rounded-xl overflow-hidden border border-emerald-500/30 w-24 h-24 group">
                    <img src={selectedImage} alt="Preview" className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                      <button 
                        onClick={() => { setSelectedImage(null); if(fileInputRef.current) fileInputRef.current.value = ''; }}
                        className="p-1 rounded-full bg-red-500/80 text-white hover:bg-red-500"
                      >
                        <XCircle className="w-5 h-5" />
                      </button>
                    </div>
                  </div>
                </MotionDiv>
              )}
            </AnimatePresence>

            <div className="flex flex-col gap-3">
              <div className="relative flex items-end gap-2 bg-white/5 border border-white/10 rounded-xl md:rounded-2xl p-2 md:p-3 focus-within:border-emerald-500/50 focus-within:ring-1 focus-within:ring-emerald-500/20 transition-all">
                {/* 隐藏的文件输入框 */}
                <input 
                  type="file" 
                  accept="image/*" 
                  ref={fileInputRef} 
                  onChange={handleFileSelect} 
                  className="hidden" 
                />

                {/* 上传按钮 */}
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className={`p-2 rounded-lg transition-colors shrink-0 mb-0.5 ${selectedImage ? 'text-emerald-400 bg-emerald-500/10' : 'text-white/40 hover:text-white hover:bg-white/10'}`}
                  title="上传图片 (例如: 学生作文照片)"
                >
                  <ImageIcon className="w-5 h-5" />
                </button>

                <textarea
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' && !e.shiftKey && window.innerWidth > 768) {
                      e.preventDefault();
                      handleSend();
                    }
                  }}
                  rows={1}
                  placeholder={selectedImage ? "已添加图片，可输入批改要求..." : "在此输入您的备课需求或粘贴文本..."}
                  className="w-full bg-transparent border-none text-xs md:text-sm focus:outline-none focus:ring-0 placeholder:text-white/20 resize-none min-h-[44px] py-3 max-h-[120px]"
                  style={{ height: 'auto' }}
                />

                <button 
                  onClick={() => handleSend()}
                  disabled={(!input.trim() && !selectedImage) || isLoading}
                  className="p-2.5 bg-emerald-600 text-white rounded-lg hover:bg-emerald-500 transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-emerald-600/40 shrink-0 mb-0.5"
                >
                  <Send className="w-4 h-4 md:w-5 md:h-5" />
                </button>
              </div>

              <div className="flex flex-col md:flex-row md:justify-between md:items-center gap-2 px-1">
                <p className="text-[9px] md:text-[11px] text-white/20">
                  语枢 AI 可能会产生误差，请结合教材进行人工核校。
                </p>
                {isExpertMode && (
                  <span className="text-[9px] md:text-[10px] text-purple-400 font-bold flex items-center gap-1">
                    <Zap className="w-2.5 h-2.5" /> 专家通道已连接
                  </span>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

